#!/usr/bin/env bash
# =============================================================================
#  execute_all.sh
#  GENERATED by submodules/D_compile_and_generate_shell_script.ps1 -- do not edit.
#
#  Single entry point. Asks the stage questions UP FRONT (each question and its
#  options are shown), runs the chosen stages UNATTENDED in this order:
#    drivers -> settings(pre) -> applications -> manual downloads -> settings(post) -> docker
#  settings(post) recreates shortcuts/pins, ~/.ssh and Contacts after apps exist.
#  Manual downloads place each file, then 'done'/'skip'; docker rebuild is optional.
#  Usage:  sudo ./execute_all.sh
# =============================================================================
# =============================================================================
#  _common.sh  --  universal runtime engine for the generated installer scripts
# -----------------------------------------------------------------------------
#  This file is INLINED into every generated script in "Execute on Linux!/" by
#  submodules/D_compile_and_generate_shell_script.ps1.  It is distro- and
#  architecture-agnostic: it detects the running distro FAMILY (apt/dnf/zypper/
#  pacman) and CPU ARCH at runtime, then dispatches installs accordingly.
#
#  Design: Flatpak-first.  GUI apps come from Flathub (identical app id on every
#  distro).  The native package manager is used only for the irreducible base
#  (installing Flatpak itself, CLI/dev tools, drivers, system bits).
# =============================================================================

# Be strict but survivable: we handle per-app failures ourselves, so do not let
# a single failing install abort the whole run.
set -o pipefail

# ----------------------------- pretty output ---------------------------------
# All human-facing chatter goes to fd 3 (stdout) so command output can be hidden.
exec 3>&1
log()  { printf '\n\033[1;34m==>\033[0m %s\n' "$*" >&3; }
info() { printf '       %s\n' "$*" >&3; }
ok()   { printf '       \033[32m%s\033[0m\n' "$*" >&3; }
warn() { printf '       \033[1;33m%s\033[0m\n' "$*" >&3; }
err()  { printf '\033[1;31m%s\033[0m\n' "$*" >&3; }
# Purple/magenta line -- used for the interactive wine (Windows emulator) first-launch
# appearance-tuning prompts so they stand out from ordinary install chatter.
purple() { printf '\033[1;35m%s\033[0m\n' "$*" >&3; }

# Project banner -- printed ONCE at the very start of a run, mirroring the PowerShell
# Show-MegaTitle that run_project.ps1 shows on the Windows side. Green.
mega_title() {
  local g=$'\033[1;32m' r=$'\033[0m'
  printf '%s\n' '' >&3
  printf '%s  ###########################################################%s\n' "$g" "$r" >&3
  printf '%s  ##                                                       ##%s\n' "$g" "$r" >&3
  printf '%s  ##            M I G R A T E   T O   L I N U X             ##%s\n' "$g" "$r" >&3
  printf '%s  ##        Windows  ->  Linux   Migration  Toolkit         ##%s\n' "$g" "$r" >&3
  printf '%s  ##                                                       ##%s\n' "$g" "$r" >&3
  printf '%s  ###########################################################%s\n' "$g" "$r" >&3
  printf '%s\n' '' >&3
}

# Sensitive data exported on Windows (WiFi passwords, SSH private keys, Contacts,
# wallpaper) is OpenSSL-encrypted with ONE shared password. Ask for it ONCE, up front,
# and cache it in MIGRATE_XFER_PWD so each consumer (apply_wifi, unpack_stage) reuses the
# same answer instead of prompting again mid-run. Idempotent; the flag and the answer are
# exported so child stages launched by execute_all inherit them and never re-ask.
XFER_PWD_ASKED="${XFER_PWD_ASKED:-0}"

# Non-interactive transfer password: "--dec_pwd SECRET" or "--dec_pwd=SECRET" on the
# command line supplies the sensitive-data DECRYPTION password up front (it pairs with the
# Windows-side exporter's --enc_pwd). When given, ask_xfer_password uses it and NEVER
# prompts. We strip the flag (and its value) from the positional parameters here -- at top
# level, before any script's own main "$@" runs -- so the rest of the argument parsing is
# unaffected. The rotate keeps the remaining args in order and preserves ones with spaces.
MIGRATE_XFER_PWD_PROVIDED="${MIGRATE_XFER_PWD_PROVIDED:-0}"
if [ "$#" -gt 0 ]; then
  _xp_n=$#; _xp_pend=0
  while [ "$_xp_n" -gt 0 ]; do
    _xp_a="$1"; shift; _xp_n=$((_xp_n - 1))
    if [ "$_xp_pend" = 1 ]; then
      MIGRATE_XFER_PWD="$_xp_a"; MIGRATE_XFER_PWD_PROVIDED=1; _xp_pend=0; continue
    fi
    case "$_xp_a" in
      --dec_pwd=*) MIGRATE_XFER_PWD="${_xp_a#--dec_pwd=}"; MIGRATE_XFER_PWD_PROVIDED=1 ;;
      --dec_pwd)   _xp_pend=1 ;;
      *) set -- "$@" "$_xp_a" ;;
    esac
  done
  export MIGRATE_XFER_PWD MIGRATE_XFER_PWD_PROVIDED
  unset _xp_a _xp_n _xp_pend
fi

# Best-effort verification that a candidate transfer password actually decrypts the
# sensitive-data archive C_detect produced next to the staging dir (same AES-256-CBC /
# PBKDF2 scheme unpack_stage uses). Exit status:
#   0 = verified correct   1 = verified WRONG   2 = cannot verify (no archive / no tools)
# This lets ask_xfer_password catch a mistyped password up front instead of failing
# silently later when the WiFi/SSH/Contacts restore steps try to use it.
xfer_pwd_check() {
  local pw="$1" archive="${MIGRATE_STAGE}.tar.enc"
  [ -f "$archive" ] || return 2
  have_cmd openssl && have_cmd tar || return 2
  if openssl enc -d -aes-256-cbc -pbkdf2 -salt -pass pass:"$pw" -in "$archive" 2>/dev/null \
       | tar -tf - >/dev/null 2>&1; then
    return 0
  fi
  return 1
}

ask_xfer_password() {
  [ "$XFER_PWD_ASKED" = "1" ] && return 0
  XFER_PWD_ASKED=1; export XFER_PWD_ASKED
  # Supplied non-interactively via --dec_pwd: use it as-is and never prompt.
  [ "${MIGRATE_XFER_PWD_PROVIDED:-0}" = "1" ] && { export MIGRATE_XFER_PWD; return 0; }
  [ -r /dev/tty ] || { export MIGRATE_XFER_PWD; return 0; }

  local RED=$'\033[1;31m' YEL=$'\033[1;33m' RST=$'\033[0m' ans tries=0 max=3
  local archive="${MIGRATE_STAGE}.tar.enc"

  # Nothing encrypted to restore -> don't bother asking for a password at all.
  if [ ! -f "$archive" ]; then
    warn "Warning! No encrypted sensitive-data archive was found - there is nothing to restore. Continuing ..."
    export MIGRATE_XFER_PWD=""
    return 0
  fi

  # openssl is required to decrypt that archive. If it is missing, offer to install
  # it now; if the user declines (or the install fails), skip the password prompt.
  if ! have_cmd openssl; then
    printf '\n%s  OpenSSL is %srequired%s to restore your sensitive data. It is highly recommended that you install it now (y/n). %s' "$YEL" "$RED" "$YEL" "$RST" > /dev/tty
    while :; do
      read -r ans < /dev/tty || ans="n"
      case "$ans" in
        [Yy]*)
          pm_refresh
          if capture pm_install openssl && have_cmd openssl; then
            ok "installed: openssl"
          else
            warn "Warning! OpenSSL could not be installed, thus your sensitive data cannot be restored. Continuing ..."
            export MIGRATE_XFER_PWD=""; return 0
          fi
          break ;;
        [Nn]*)
          warn "Warning! OpenSSL is not installed, thus your sensitive data cannot be restored. Continuing ..."
          export MIGRATE_XFER_PWD=""; return 0 ;;
        *) printf '%s  Please answer y or n: %s' "$RED" "$RST" > /dev/tty ;;
      esac
    done
  fi

  while :; do
    printf '  Enter the password used on Windows to encrypt your sensitive data (WiFi passwords, SSH keys, Contacts, wallpaper). Leave empty to skip restoring it: ' > /dev/tty
    # -s masks the typed password; it also swallows the Enter, so echo our own newline.
    read -rs MIGRATE_XFER_PWD < /dev/tty || MIGRATE_XFER_PWD=""
    printf '\n' > /dev/tty
    tries=$((tries + 1))
    # Always pause a beat after an entry so the outcome is visible / not jarring.
    sleep 1
    # A blank answer is an intentional "skip restore" -- nothing to verify.
    [ -z "$MIGRATE_XFER_PWD" ] && break
    # 0 = correct, 2 = un-verifiable (no archive/tools) -> accept either silently.
    xfer_pwd_check "$MIGRATE_XFER_PWD"
    case $? in 0|2) break ;; esac

    # Verified WRONG. Up to $max total entries get a retry; after that, fall back to
    # the plain continue/exit choice with a note on how to still restore the data.
    if [ "$tries" -lt "$max" ]; then
      printf '%s  Password entered incorrectly! (r)etry, (c)ontinue without restoring your sensitive data, or (e)xit? %s' "$RED" "$RST" > /dev/tty
      while :; do
        read -r ans < /dev/tty || ans="e"
        case "$ans" in
          [Rr]*) break ;;                        # back to the top: ask the password again
          [Cc]*) MIGRATE_XFER_PWD=""; break 2 ;;  # continue without restoring
          [Ee]*) exit 1 ;;                        # quit the script
          *) printf '%s  Please answer r, c or e: %s' "$RED" "$RST" > /dev/tty ;;
        esac
      done
    else
      printf '%s  Password entered incorrectly! (c)ontinue without restoring your sensitive data, or (e)xit?  To restore it you must exit now (e) and re-run the script. %s' "$RED" "$RST" > /dev/tty
      while :; do
        read -r ans < /dev/tty || ans="e"
        case "$ans" in
          [Cc]*) MIGRATE_XFER_PWD=""; break 2 ;;  # continue without restoring
          [Ee]*) exit 1 ;;                        # quit the script
          *) printf '%s  Please answer c or e: %s' "$RED" "$RST" > /dev/tty ;;
        esac
      done
    fi
  done

  export MIGRATE_XFER_PWD
}

have_cmd() { command -v "$1" >/dev/null 2>&1; }

# Filesystem-safe slug from an app name. execute_all.sh stages user-supplied
# files for "manual" apps under $MIGRATE_MANUAL_DIR/<slug>/ using the SAME slug.
slugify() { printf '%s' "$1" | tr '[:upper:] ' '[:lower:]-' | tr -cd 'a-z0-9-_'; }

# The non-root user we should install Flatpak apps / write desktop files for,
# even though the script itself runs under sudo. logname is the original login
# name of the session and is more reliable than $SUDO_USER (which is empty when
# the script is not entered through sudo, and can be stale across su/sudo chains).
TARGET_USER="$(logname 2>/dev/null || true)"
{ [ -z "$TARGET_USER" ] || [ "$TARGET_USER" = "root" ]; } && TARGET_USER="${SUDO_USER:-$(id -un)}"
TARGET_HOME="$(getent passwd "$TARGET_USER" 2>/dev/null | cut -d: -f6)"
[ -z "$TARGET_HOME" ] && TARGET_HOME="$HOME"

# ----------------------------- bookkeeping -----------------------------------
# The results log is created on the logname user's Desktop (and owned by them) so it is
# easy to find after the run; it falls back to a temp file if that is not writable.
RESULTS="${RESULTS:-$TARGET_HOME/Desktop/migrate_to_linux_results.tsv}"
# execute_all sets MIGRATE_KEEP_RESULTS so the per-stage child scripts APPEND to one
# shared log instead of truncating it, which lets execute_all print a combined
# summary of every operation at the very end. Run standalone, a script truncates.
if [ -z "${MIGRATE_KEEP_RESULTS:-}" ]; then
  mkdir -p "$(dirname "$RESULTS")" 2>/dev/null || true
  if : > "$RESULTS" 2>/dev/null; then
    chown "$TARGET_USER":"$TARGET_USER" "$RESULTS" 2>/dev/null || true
  else
    RESULTS="$(mktemp)"
  fi
fi
# Containers launched by the docker install method are recorded here (one TSV row per
# container: winapp \t image \t container \t how-to) so the end-of-run summary can print
# a "Launched containers" section. Shares the same cross-stage model as RESULTS.
DOCKER_LAUNCHED="${DOCKER_LAUNCHED:-/tmp/migrate_to_linux_launched.tsv}"
if [ -z "${MIGRATE_KEEP_RESULTS:-}" ]; then
  : > "$DOCKER_LAUNCHED" 2>/dev/null || DOCKER_LAUNCHED="$(mktemp)"
fi
# Install ledger: one TSV row per successful install (method <tab> identifier). Used to
# generate an uninstall script at the end of the run. Shares the cross-stage model above.
LEDGER="${LEDGER:-/tmp/migrate_to_linux_ledger.tsv}"
if [ -z "${MIGRATE_KEEP_RESULTS:-}" ]; then
  : > "$LEDGER" 2>/dev/null || LEDGER="$(mktemp)"
fi
declare -a OK_LIST=() SKIP_LIST=() FAIL_LIST=() FAIL_REASON=() MANUAL_LIST=() PLAN_LIST=() UNVERIFIED_LIST=()

# Report-only mode: when MIGRATE_DRY_RUN=yes the engine prints the plan and makes no changes.
is_dry_run() { [ "${MIGRATE_DRY_RUN:-no}" = "yes" ]; }

# LAST_ERR holds the 1-line reason from the most recent captured command failure.
LAST_ERR=""

# --- per-operation skip key (Ctrl+I / Command+I) -----------------------------
# A keyboard interrupt that aborts ONLY the current operation -- the application
# being installed right now -- without stopping the whole script (that stays on
# Ctrl+C). Ctrl+I emits the TAB byte (0x09) in every terminal, and Command+I on
# macOS terminals sends the same byte, so we watch the controlling terminal for
# a TAB while each long operation runs and, when seen, kill just that operation's
# process group and mark the app skipped. SKIPPED_BY_USER is the cross-call flag:
# _install_app_core resets it per app and honours it instead of failing the app.
SKIP_KEY_LABEL='Ctrl+I (Command+I on macOS)'
SKIP_KEY_HINT="Press \033[1;34m${SKIP_KEY_LABEL}\033[0m to skip this application"
SKIP_KEY_ENABLED="${SKIP_KEY_ENABLED:-1}"
SKIPPED_BY_USER=0
# True once the user has skipped the application currently being installed.
user_skipped() { [ "${SKIPPED_BY_USER:-0}" -eq 1 ]; }
# Whether capture can run its interruptible path (a real terminal + tools to
# create and signal a separate process group). Otherwise capture runs plainly.
skip_key_available() {
  [ "${SKIP_KEY_ENABLED:-1}" = "1" ] && [ -r /dev/tty ] && have_cmd ps
}

# Run a command, show its output, and on failure capture the last output line into
# LAST_ERR (a 1-line error reason). stdin stays attached, so interactive installers
# still work. Returns the command's real exit code. When a terminal is present the
# command runs interruptibly so the user can skip just this application (see above).
capture() {
  if is_dry_run; then printf '       \033[2m[dry-run] would run: %s\033[0m\n' "$*" >&3; LAST_ERR=""; return 0; fi
  # Already skipped earlier in this same app? Make every later step a no-op so the
  # install winds down quickly to the "skipped" verdict instead of trying more routes.
  if user_skipped; then LAST_ERR="skipped by user ($SKIP_KEY_LABEL)"; return 130; fi
  local rc tmp; tmp="$(mktemp 2>/dev/null || echo /tmp/mtl_cap.$$)"

  # Confirm the controlling terminal is actually usable for INPUT before going
  # interruptible: it can look readable (-r) yet error on read in non-interactive
  # runs, which would otherwise spin the poll loop. The probe runs in a subshell
  # (its stderr discarded) so a failed open neither pollutes our fds nor leaks.
  if ! skip_key_available || ! ( exec 8</dev/tty ) 2>/dev/null; then
    "$@" 2>&1 | tee "$tmp" >&3
    rc=${PIPESTATUS[0]}
  else
    # Tell the user how to skip, then run the command in its own process group so
    # that a skip can take down the command AND its children (curl, the package
    # manager, ...) while leaving this script untouched. The command's real exit
    # code is smuggled out through $rcf because a backgrounded pipeline does not
    # expose PIPESTATUS. The command gets no terminal (stdin /dev/null, fd 8
    # closed) so it cannot steal the skip keystroke we are polling for. fd 8 is
    # opened by the poll block itself (block-scoped, so it auto-closes cleanly).
    printf '       %b\n' "$SKIP_KEY_HINT" >&3
    local rcf tab; rcf="$(mktemp 2>/dev/null || echo /tmp/mtl_rc.$$)"; tab="$(printf '\t')"
    set -m 2>/dev/null
    { "$@" </dev/null 8<&- 2>&1; echo $? > "$rcf"; } | tee "$tmp" >&3 &
    local pl=$! pgid key
    set +m 2>/dev/null
    pgid="$(ps -o pgid= -p "$pl" 2>/dev/null | tr -d ' ')"; [ -n "$pgid" ] || pgid="$pl"
    {
      while kill -0 "$pl" 2>/dev/null; do
        key=""; IFS= read -rsn1 -t 1 -u 8 key 2>/dev/null
        if [ "$key" = "$tab" ]; then
          SKIPPED_BY_USER=1
          # Tear down the whole operation: SIGINT first (lets curl/apt clean up),
          # then SIGTERM, then SIGKILL. The leading "-" targets the process group.
          kill -INT  "-$pgid" 2>/dev/null; sleep 0.3
          kill -TERM "-$pgid" 2>/dev/null; sleep 0.2
          kill -KILL "-$pgid" 2>/dev/null
          printf '\n       \033[1;33mskipping this application ...\033[0m\n' >&3
          break
        fi
      done
    } 8</dev/tty
    wait "$pl" 2>/dev/null
    rc="$(cat "$rcf" 2>/dev/null)"; [ -n "$rc" ] || rc=1
    user_skipped && rc=130
    rm -f "$rcf" 2>/dev/null || true
  fi

  LAST_ERR=""
  if user_skipped; then
    LAST_ERR="skipped by user ($SKIP_KEY_LABEL)"
  elif [ "$rc" -ne 0 ]; then
    LAST_ERR="$(grep -v '^[[:space:]]*$' "$tmp" 2>/dev/null | tail -n 1)"
    [ -z "$LAST_ERR" ] && LAST_ERR="exit code $rc"
  fi
  rm -f "$tmp" 2>/dev/null || true
  return "$rc"
}

# MODULE tags which big module (Drivers / Config settings / Applications) each result
# belongs to, so execute_all can print a per-module classified summary at the end.
MODULE="${MODULE:-General}"
record_line() { printf '%s\t%s\t%-6s\t%s\t%s\t%s\t%s\n' "$(date '+%F %T')" "${MODULE:-General}" "$1" "$2" "${3:-}" "${4:-}" "${5:-}" >> "$RESULTS"; }
# One-line "how to open this app" hint, derived from how it was installed. Used by the
# end-of-run summary to tell the user how to launch each app that now exists.
launch_hint_from_detail() {  # launch_hint_from_detail NAME DETAIL
  local nm="$1" d="$2" id
  case "$d" in
    flatpak\ *) id="${d#flatpak }"; id="${id%% *}"; printf 'Search "%s" in the start menu, or run "flatpak run %s" in a terminal' "$nm" "$id" ;;
    native\ *)  id="${d#native }";  id="${id%% *}"; printf 'Search "%s" in the start menu, or run "%s" in a terminal' "$nm" "$id" ;;
    snap\ *)    id="${d#snap }";    id="${id%% *}"; printf 'Search "%s" in the start menu, or run "%s" in a terminal' "$nm" "$id" ;;
    web-app*)            printf 'Search "%s" in the start menu (web-app shortcut)' "$nm" ;;
    *wine*)              printf 'Search "%s" in the start menu (wine - Windows emulator launcher)' "$nm" ;;
    *docker*|*ontainer*) printf '"%s" runs as a Docker container - open its web UI or manage it with docker' "$nm" ;;
    *)                   printf 'Search "%s" in the start menu, or run "%s" in a terminal' "$nm" "$nm" ;;
  esac
}
# Return STRING with any "already <state>" status phrase (already installed / configured /
# present / set / enabled / exists / running / ...) shown in green; the optional 2nd arg is
# the colour to RESUME with after the phrase, so the rest of the line keeps its original
# colour (default: reset). On-screen use only -- the raw phrase is what is written to the log.
hl_already() {  # hl_already STRING [RESUME_COLOUR]
  local g=$'\033[32m' rst=$'\033[0m' back
  back="${2:-$rst}"
  printf '%s' "$1" | sed -E "s/already [A-Za-z]+/${g}&${back}/g"
}

# mark_ok WIN_NAME [DETAIL] [ALT_NAME] [LAUNCH_OVERRIDE]. The summary shows the app as
# "<alt> (<win>): <launch hint>"; the hint is the manifest launch override if given,
# else derived from how it was installed using the ALTERNATIVE name (what to search for).
mark_ok()     { OK_LIST+=("$1"); local _alt="${3:-}" _h=""; if [ "${MODULE:-}" = "Applications" ]; then if [ -n "${4:-}" ]; then _h="$4"; else _h="$(launch_hint_from_detail "${_alt:-$1}" "${2:-}")"; fi; fi; record_line OK "$1" "${2:-}" "$_h" "$_alt"; ok "installed: ${_alt:-$1}${2:+  ->  $2}"; }
mark_skip()   { SKIP_LIST+=("$1");   record_line SKIP   "$1" "${2:-}" "${3:-}" "${4:-}"; info "skipped: $1 ($(hl_already "${2:-already present}"))"; }
mark_fail()   { FAIL_LIST+=("$1"); FAIL_REASON+=("${2:-unknown error}"); record_line FAIL "$1" "${2:-}"; err "failed: $1 ${2:+- $2}"; }
mark_manual() { MANUAL_LIST+=("$1"); record_line MANUAL "$1" "${2:-}"; warn "manual step required: $1 ${2:+- $2}"; }
mark_plan()      { PLAN_LIST+=("$1");       record_line PLAN  "$1" "${2:-}"; info "[dry-run] would install: $1 ${2:+- $2}"; }
mark_unverified(){ UNVERIFIED_LIST+=("$1"); record_line UNVER "$1" "${2:-}"; warn "installed but UNVERIFIED: $1 ${2:+- $2}"; }

# Record a successful install in the ledger (method <tab> id) so an uninstall script can
# be generated later. No-op in dry-run.
ledger_add() { is_dry_run && return 0; printf '%s\t%s\n' "$1" "${2:-}" >> "$LEDGER" 2>/dev/null || true; }

# Verify an install is actually present after the package manager reported success.
verify_present() {  # verify_present METHOD ID  -> 0 if present
  case "$1" in
    flatpak) have_cmd flatpak && flatpak_installed "$2" ;;
    native)  pm_installed "${2%% *}" ;;
    snap)    have_cmd snap && snap list "${2%% *}" >/dev/null 2>&1 ;;
    *)       return 0 ;;   # file/wine/webapp/docker: nothing to verify -> assume ok
  esac
}

# Record a successful install: verify it is really present, ledger it for uninstall, and
# mark OK -- or mark it UNVERIFIED if the post-install check cannot confirm it.
finish_install() {  # finish_install NAME ALT METHOD ID DETAIL [LAUNCH]
  local name="$1" alt="$2" method="$3" id="$4" detail="$5" launch="${6:-}"
  if verify_present "$method" "$id"; then
    ledger_add "$method" "$id"; mark_ok "$name" "$detail" "$alt" "$launch"
  else
    mark_unverified "${alt:-$name}" "$detail (could not confirm it is installed)"
  fi
}

# Write an uninstall script for everything this run installed. Package-manager installs
# are reversible; file/wine installs get a manual note. No-op in dry-run / empty ledger.
write_uninstall_script() {
  is_dry_run && return 0
  [ -s "$LEDGER" ] || return 0
  local out="${MIGRATE_UNINSTALL_SCRIPT:-$TARGET_HOME/uninstall_migrated_apps.sh}" rm_native="" m id
  case "$PM" in
    apt)    rm_native="apt-get remove -y" ;;
    dnf)    rm_native="dnf remove -y" ;;
    zypper) rm_native="zypper --non-interactive remove" ;;
    pacman) rm_native="pacman -Rns --noconfirm" ;;
  esac
  {
    printf '#!/usr/bin/env bash\n'
    printf '# Auto-generated by the Migration Toolkit -- removes what the install run added.\n'
    printf '# Review it, then run as root:  sudo bash %s\n\n' "$out"
    printf 'set -o pipefail\n\n'
    sort -u "$LEDGER" 2>/dev/null | while IFS="$(printf '\t')" read -r m id; do
      [ -n "$id" ] || continue
      case "$m" in
        flatpak) printf 'flatpak uninstall -y %s\n' "$id" ;;
        native)  printf '%s %s\n' "$rm_native" "$id" ;;
        snap)    printf 'snap remove %s\n' "$id" ;;
        wine)    printf '# wine (Windows emulator) app -- to remove, delete its prefix:  rm -rf %s\n' "$id" ;;
        file)    printf '# installed from a downloaded file (remove manually): %s\n' "$id" ;;
        *)       printf '# %s: %s\n' "$m" "$id" ;;
      esac
    done
  } > "$out" 2>/dev/null && { chmod +x "$out" 2>/dev/null || true; chown "$TARGET_USER":"$TARGET_USER" "$out" 2>/dev/null || true; info "Uninstall script written: $out"; }
}

print_summary() {
  # When orchestrated by execute_all, it prints ONE combined, classified summary at
  # the very end; suppress the per-stage summary here to avoid mid-run clutter.
  [ -n "${MIGRATE_KEEP_RESULTS:-}" ] && return 0
  log "Summary"
  info "OK:        ${#OK_LIST[@]}"
  info "Skip:      ${#SKIP_LIST[@]}"
  info "Manual:    ${#MANUAL_LIST[@]}"
  info "Unverified:${#UNVERIFIED_LIST[@]}"
  info "Failed:    ${#FAIL_LIST[@]}"
  [ "${#PLAN_LIST[@]}" -gt 0 ] && info "Planned (dry-run): ${#PLAN_LIST[@]}"
  if [ "${#UNVERIFIED_LIST[@]}" -gt 0 ]; then
    warn "Installed but UNVERIFIED (could not confirm present):"; for i in "${UNVERIFIED_LIST[@]}"; do info "  - $i"; done
  fi
  if [ "${#FAIL_LIST[@]}" -gt 0 ]; then
    warn "Failures (1-line reason each):"
    for i in "${!FAIL_LIST[@]}"; do err "  - ${FAIL_LIST[$i]}: ${FAIL_REASON[$i]}"; done
  fi
  if [ "${#MANUAL_LIST[@]}" -gt 0 ]; then
    warn "Need a manual step:"; for i in "${MANUAL_LIST[@]}"; do info "  - $i"; done
  fi
  # Apps that now exist on the machine (installed this run or already present), each
  # with a one-line how-to-open note (field 6 of the results log).
  if awk -F'\t' '$6!=""{f=1} END{exit !f}' "$RESULTS" 2>/dev/null; then
    log "Applications on this machine - how to open each"
    awk -F'\t' '$6!=""{n=($7!="" && $7!=$4 ? $7" ("$4")" : $4); printf "  %s: %s\n",n,$6}' "$RESULTS" | sort -u | while IFS= read -r l; do info "$l"; done
  fi
  print_launched_containers
  write_uninstall_script
  info "Full log: $RESULTS"
}

require_root() {
  if [ "$(id -u)" -ne 0 ]; then
    err "This script must be run as root.  Try:  sudo $0"
    exit 1
  fi
}

# ----------------------------- optional additions ----------------------------
# Some migrated settings (e.g. firewall rules, display resolution, NTP) need a
# package that may not be installed. ask_install_addition explains WHAT the
# package is for and offers yes / skip / skip all, mirroring the skip-all model
# used by manual_fallback. Returns 0 if the package(s) are now present (user said
# yes and the install succeeded), 1 otherwise (skipped, no tty, or install failed).
#   ask_install_addition "Display resolution" "x11-xserver-utils" "set the screen resolution"
ADDITIONS_SKIP_ALL=0
ask_install_addition() {  # ask_install_addition PURPOSE_LABEL "PKG [PKG...]" WHAT_FOR
  local label="$1" pkgs="$2" whatfor="$3" ans
  [ "${ADDITIONS_SKIP_ALL:-0}" = "1" ] && { mark_skip "$label" "addition skipped (skip all)"; return 1; }
  if is_dry_run; then info "[dry-run] would offer to install: $pkgs (for $label)"; return 1; fi
  printf '\n\033[1;34m==> %s needs an extra package\033[0m\n' "$label" >&3
  info "The package(s) \"$pkgs\" are required to ${whatfor}."
  info "They come from your distribution's own repositories ($PM)."
  if [ ! -r /dev/tty ]; then mark_skip "$label" "addition needs \"$pkgs\" (no tty to ask)"; return 1; fi
  while :; do
    printf '  Install %s now? (y=yes / s=skip / a=skip all): ' "$pkgs" > /dev/tty
    read -r ans < /dev/tty || ans="s"
    case "$ans" in
      [Yy]|[Yy][Ee][Ss])
        pm_refresh
        # shellcheck disable=SC2086
        if capture pm_install $pkgs; then ok "installed: $pkgs"; return 0
        else mark_fail "$label" "${LAST_ERR:-could not install $pkgs}"; return 1; fi ;;
      [Aa]|[Aa][Ll][Ll]|'skip all'|'Skip all'|'Skip All'|'SKIP ALL')
        ADDITIONS_SKIP_ALL=1; mark_skip "$label" "addition skipped (skip all)"; return 1 ;;
      [Ss]|[Ss][Kk][Ii][Pp]) mark_skip "$label" "addition skipped (needs $pkgs)"; return 1 ;;
      *) printf '\033[1;31m  Please answer y (yes), s (skip), or a (skip all).\033[0m\n' > /dev/tty ;;
    esac
  done
}

# =============================================================================
#  DISTRO + ARCHITECTURE DETECTION
# =============================================================================
FAMILY=""      # debian | rhel | suse | arch
PM=""          # apt | dnf | zypper | pacman
DISTRO_ID=""
DISTRO_NAME=""

detect_distro() {
  if [ -r /etc/os-release ]; then
    # shellcheck disable=SC1091
    . /etc/os-release
    DISTRO_ID="${ID:-}"
    DISTRO_NAME="${PRETTY_NAME:-${NAME:-$ID}}"
  fi
  local hay=" ${DISTRO_ID} ${ID_LIKE:-} "
  case "$hay" in
    *" debian "*|*" ubuntu "*|*" linuxmint "*|*" pop "*|*" zorin "*|*" elementary "*) FAMILY="debian"; PM="apt" ;;
    *" rhel "*|*" fedora "*|*" centos "*|*" rocky "*|*" almalinux "*|*" ol "*) FAMILY="rhel"; PM="dnf" ;;
    *" suse "*|*" opensuse "*|*" sles "*|*" sled "*) FAMILY="suse"; PM="zypper" ;;
    *" arch "*|*" archlinux "*|*" manjaro "*|*" endeavouros "*) FAMILY="arch"; PM="pacman" ;;
    *)
      # Fall back to whichever package manager actually exists.
      if   have_cmd apt-get; then FAMILY="debian"; PM="apt"
      elif have_cmd dnf;     then FAMILY="rhel";   PM="dnf"
      elif have_cmd zypper;  then FAMILY="suse";   PM="zypper"
      elif have_cmd pacman;  then FAMILY="arch";   PM="pacman"
      else err "Unsupported distribution: could not find apt/dnf/zypper/pacman."; exit 1
      fi ;;
  esac
}

ARCH=""        # x86_64 | aarch64 | armhf | other
detect_arch() {
  local m; m="$(uname -m)"
  case "$m" in
    x86_64|amd64)        ARCH="x86_64" ;;
    aarch64|arm64)       ARCH="aarch64" ;;
    armv7l|armhf|armv6l) ARCH="armhf" ;;
    *)                   ARCH="$m" ;;
  esac
}

# arch_supported "x86_64 aarch64"  ->  true if $ARCH is listed (empty list = all)
arch_supported() {
  local list="$1"
  [ -z "$list" ] && return 0
  case " $list " in *" $ARCH "*) return 0 ;; *) return 1 ;; esac
}

# =============================================================================
#  PACKAGE-MANAGER ABSTRACTION
# =============================================================================
# Quarantine malformed apt source files so a single bad entry can't wedge the
# whole package manager. apt aborts every update/install if any file in
# sources.list.d has a bare "deb"/"deb-src" line with no URI -- which is exactly
# what a third-party installer (e.g. NordVPN) leaves behind when interrupted
# mid-write (Ctrl+C). We only touch clearly-broken files, and we rename rather
# than delete (.broken) so the change is reversible.
apt_repair_sources() {
  [ -d /etc/apt/sources.list.d ] || return 0
  for f in /etc/apt/sources.list.d/*.list; do
    [ -f "$f" ] || continue   # no matches -> literal glob, skip
    # A line that is just "deb"/"deb-src" (optionally with [opts]) and nothing
    # after it -- no URI, no suite -- is malformed and fatal to apt.
    if grep -qE '^[[:space:]]*deb(-src)?([[:space:]]+\[[^]]*\])?[[:space:]]*$' "$f"; then
      warn "Malformed apt source quarantined: $f -> $f.broken"
      is_dry_run || mv -f "$f" "$f.broken"
    fi
  done
}

_PM_REFRESHED=0
pm_refresh() {
  [ "$_PM_REFRESHED" = "1" ] && return 0
  case "$PM" in
    apt)    apt_repair_sources; DEBIAN_FRONTEND=noninteractive apt-get update -y ;;
    dnf)    dnf -y makecache ;;
    zypper) zypper --non-interactive refresh ;;
    pacman) pacman -Sy --noconfirm ;;
  esac
  _PM_REFRESHED=1
}

pm_install() {
  [ "$#" -eq 0 ] && return 0
  case "$PM" in
    apt)    DEBIAN_FRONTEND=noninteractive apt-get install -y --no-install-recommends "$@" ;;
    dnf)    dnf install -y "$@" ;;
    zypper) zypper --non-interactive install -y --no-recommends "$@" ;;
    pacman) pacman -S --noconfirm --needed "$@" ;;
  esac
}

pm_installed() {
  case "$PM" in
    apt)    dpkg-query -W -f='${Status}' "$1" 2>/dev/null | grep -q "install ok installed" ;;
    dnf)    rpm -q "$1" >/dev/null 2>&1 ;;
    zypper) rpm -q "$1" >/dev/null 2>&1 ;;
    pacman) pacman -Q "$1" >/dev/null 2>&1 ;;
  esac
}

# =============================================================================
#  FLATPAK (universal app layer)
# =============================================================================
ensure_flatpak() {
  if ! have_cmd flatpak; then
    log "Installing Flatpak (required for the universal app layer)"
    pm_refresh
    pm_install flatpak || { mark_fail "flatpak" "could not install flatpak via $PM"; return 1; }
  fi
  flatpak remote-add --if-not-exists flathub https://dl.flathub.org/repo/flathub.flatpakrepo >/dev/null 2>&1 || true
  return 0
}

flatpak_installed() { flatpak info "$1" >/dev/null 2>&1; }

install_flatpak() {  # install_flatpak APPID
  local id="$1"
  if flatpak_installed "$id"; then
    # Already present: update it if the user asked to update existing apps.
    [ "${MIGRATE_UPDATE_EXISTING:-no}" = "yes" ] && flatpak update -y --noninteractive "$id"
    return 0
  fi
  flatpak install -y --noninteractive flathub "$id"
}

# =============================================================================
#  SNAP (optional fallback)
# =============================================================================
ensure_snap() {
  have_cmd snap && return 0
  case "$PM" in
    apt)    pm_install snapd ;;
    dnf)    pm_install snapd && systemctl enable --now snapd.socket 2>/dev/null && ln -sf /var/lib/snapd/snap /snap 2>/dev/null ;;
    zypper) warn "snap on openSUSE needs the snappy repo; skipping snap fallback"; return 1 ;;
    pacman) warn "snap on Arch is via AUR; skipping snap fallback"; return 1 ;;
  esac
  have_cmd snap
}

# =============================================================================
#  DESKTOP / WEB-APP SHORTCUTS
# =============================================================================
detect_browser() {
  local b
  for b in google-chrome google-chrome-stable chromium chromium-browser microsoft-edge brave-browser firefox; do
    have_cmd "$b" && { printf '%s' "$b"; return 0; }
  done
  # Flatpak browsers
  if flatpak_installed com.google.Chrome; then printf 'flatpak run com.google.Chrome'; return 0; fi
  if flatpak_installed org.chromium.Chromium; then printf 'flatpak run org.chromium.Chromium'; return 0; fi
  if flatpak_installed com.microsoft.Edge; then printf 'flatpak run com.microsoft.Edge'; return 0; fi
  return 1
}

# Open a URL in the desktop user's default browser (best-effort, non-blocking). Used by
# every manual / download-by-user prompt so the download page opens automatically.
open_url() {  # open_url URL
  local u="$1"; [ -n "$u" ] || return 0
  is_dry_run && return 0
  local uid; uid="$(id -u "$TARGET_USER" 2>/dev/null)"
  if have_cmd xdg-open; then
    sudo -u "$TARGET_USER" DISPLAY="${DISPLAY:-:0}" \
      DBUS_SESSION_BUS_ADDRESS="unix:path=/run/user/${uid}/bus" \
      xdg-open "$u" >/dev/null 2>&1 &
  elif have_cmd gio; then
    sudo -u "$TARGET_USER" DISPLAY="${DISPLAY:-:0}" gio open "$u" >/dev/null 2>&1 &
  fi
}

# Build a Google web-search URL for QUERY (percent-encoded). Used as the last-resort
# "download page" when no saved download URL exists or the saved one is unreachable, so
# the user is still pointed at the right place to fetch an installer.
web_search_url() {  # web_search_url QUERY
  local q="$1" out="" c i
  for (( i=0; i<${#q}; i++ )); do
    c="${q:i:1}"
    case "$c" in
      [A-Za-z0-9.~_-]) out="$out$c" ;;
      ' ')             out="$out+" ;;
      *)               out="$out$(printf '%%%02X' "'$c")" ;;
    esac
  done
  printf 'https://www.google.com/search?q=%s' "$out"
}

# Quick reachability check for a download URL. Returns 0 if the server answers without a
# conventional "broken link" error, 1 otherwise (HTTP 4xx/5xx such as 404/403/410, or a
# connection failure / DNS error / timeout -> curl code 000). Tries a HEAD first, then a
# 1-byte ranged GET for servers that reject HEAD (403/405/501). Short timeouts so a dead
# host never stalls the install. With no curl/wget available it assumes OK (let the
# browser try). No AI involved -- pure shell.
url_health_ok() {  # url_health_ok URL
  local u="$1" code=""
  [ -n "$u" ] || return 1
  case "$u" in http://*|https://*) ;; *) return 1 ;; esac
  if have_cmd curl; then
    code="$(curl -sSL -o /dev/null -m 12 -A 'Mozilla/5.0' -w '%{http_code}' -I "$u" 2>/dev/null)"
    case "$code" in
      ''|000|403|405|501) code="$(curl -sSL -o /dev/null -m 15 -A 'Mozilla/5.0' -r 0-0 -w '%{http_code}' "$u" 2>/dev/null)" ;;
    esac
  elif have_cmd wget; then
    if wget -q --spider --timeout=12 --tries=1 -U 'Mozilla/5.0' "$u" 2>/dev/null; then code=200; else code=000; fi
  else
    return 0
  fi
  case "$code" in 2*|3*) return 0 ;; *) return 1 ;; esac
}

# Open the best download page for an app in the user's browser. If URL is set AND passes
# the reachability check, open it; otherwise (missing, or a broken-link error like
# 404/403/connection failure) open a Google search for the app's installer instead. This
# is the shared "download page stage" used by manual_fallback, wine_app and the manual-
# download phase. QUERY overrides the search text (default "NAME download").
open_download_page() {  # open_download_page NAME URL [QUERY]
  local name="$1" url="$2" query="${3:-$1 download}" target=""
  if [ -n "$url" ] && url_health_ok "$url"; then
    target="$url"; info "Download page: $target"
  else
    [ -n "$url" ] && warn "saved download page is unreachable ($url) -- searching the web instead."
    target="$(web_search_url "$query")"
    info "Opening a web search for $name:"; info "  $target"
  fi
  info "(opening it in your default browser ...)"
  open_url "$target"
}

# Run a command as the logged-in desktop user with their D-Bus session / runtime dir wired
# up (per-user things like gsettings/dconf need this). Mirrors apply_settings.sh's helper
# so install_app's post-install commands can touch the user's desktop. No-op of escalation
# when already running as that user.
run_as_user() {  # run_as_user CMD [ARGS...]
  local uid; uid="$(id -u "$TARGET_USER" 2>/dev/null)"
  if [ "$(id -u)" -eq 0 ] && [ "$TARGET_USER" != "root" ]; then
    sudo -u "$TARGET_USER" \
      DBUS_SESSION_BUS_ADDRESS="unix:path=/run/user/${uid}/bus" \
      XDG_RUNTIME_DIR="/run/user/${uid}" DISPLAY="${DISPLAY:-:0}" "$@"
  else
    DBUS_SESSION_BUS_ADDRESS="${DBUS_SESSION_BUS_ADDRESS:-unix:path=/run/user/${uid}/bus}" \
      XDG_RUNTIME_DIR="${XDG_RUNTIME_DIR:-/run/user/${uid}}" DISPLAY="${DISPLAY:-:0}" "$@"
  fi
}

# Run an app's custom post-install commands (from the manifest's install.postInstall),
# best-effort, as the logged-in user, right after the app was successfully installed.
# Each command is a self-contained shell snippet; a failing one is reported but never
# fails the install. No-op in dry-run / with no commands.
run_post_install() {  # run_post_install NAME CMD [CMD...]
  local name="$1"; shift
  is_dry_run && return 0
  [ "$#" -gt 0 ] || return 0
  local cmd rc=0
  info "applying custom post-install setup for $name ..."
  for cmd in "$@"; do
    [ -n "$cmd" ] || continue
    run_as_user bash -lc "$cmd" >/dev/null 2>&1 || { rc=1; warn "a post-install command for $name did not complete (continuing): $cmd"; }
  done
  [ "$rc" -eq 0 ] && ok "custom post-install setup applied for $name"
  return 0
}

webapp_desktop() {  # webapp_desktop "Name" "URL" [ALT] [LAUNCH]
  local name="$1" url="$2" alt="${3:-}" launch="${4:-}" browser appdir desktop slug
  browser="$(detect_browser)" || { mark_manual "${alt:-$name}" "no browser found for web-app shortcut ($url)"; return 1; }
  slug="$(printf '%s' "$name" | tr '[:upper:] ' '[:lower:]-' | tr -cd 'a-z0-9-')"
  appdir="$TARGET_HOME/.local/share/applications"
  mkdir -p "$appdir"
  desktop="$appdir/webapp-$slug.desktop"
  {
    printf '[Desktop Entry]\n'
    printf 'Version=1.0\nType=Application\n'
    printf 'Name=%s\n' "$name"
    printf 'Exec=%s --app=%s\n' "$browser" "$url"
    printf 'Terminal=false\nCategories=Network;WebBrowser;\n'
  } > "$desktop"
  chown "$TARGET_USER":"$TARGET_USER" "$desktop" 2>/dev/null || true
  chmod +x "$desktop" 2>/dev/null || true
  mark_ok "$name" "web-app shortcut -> $url" "$alt" "$launch"
}

# =============================================================================
#  DIRECT DOWNLOADS (.deb / .rpm / AppImage)
# =============================================================================
DOWNLOAD_DIR="${DOWNLOAD_DIR:-/tmp/migrate_to_linux_downloads}"
mkdir -p "$DOWNLOAD_DIR" 2>/dev/null || true

download_file() {  # download_file URL OUTPATH
  local url="$1" out="$2"
  if have_cmd curl; then curl -fL --retry 3 -o "$out" "$url"
  elif have_cmd wget; then wget -O "$out" "$url"
  else err "neither curl nor wget available"; return 1; fi
}

install_local_package() {  # install_local_package FILE
  local f="$1"
  case "$PM" in
    apt)    DEBIAN_FRONTEND=noninteractive apt-get install -y "$f" || { dpkg -i "$f"; apt-get -f install -y; } ;;
    dnf)    dnf install -y "$f" ;;
    zypper) zypper --non-interactive install -y --allow-unsigned-rpm "$f" ;;
    pacman) pacman -U --noconfirm "$f" ;;
  esac
}

# Best-effort install of a package matching a specific (Windows) version. Tries the
# major-version package name and an exact version pin. Returns 0 on success, 1 if no
# matching version could be installed (caller then falls back to latest). pacman is
# rolling-release, so version pinning is not supported there.
install_native_version() {  # install_native_version PKG WINVER
  local pkg="$1" ver="$2" major
  major="$(printf '%s' "$ver" | grep -oE '[0-9]+' | head -n1)"
  [ -z "$major" ] && return 1
  case "$PM" in
    apt)    capture pm_install "${pkg}-${major}" || capture pm_install "${pkg}=${ver}" ;;
    dnf)    capture pm_install "${pkg}${major}" || capture pm_install "${pkg}-${major}" || capture pm_install "${pkg}-${ver}" ;;
    zypper) capture pm_install "${pkg}${major}" || capture pm_install "${pkg}-${ver}" ;;
    pacman) return 1 ;;
  esac
}

# =============================================================================
#  install_app  --  the multi-strategy, Flatpak-first dispatcher
# -----------------------------------------------------------------------------
#  Usage (emitted by the generator):
#    install_app --name "VLC" --method flatpak --flatpak org.videolan.VLC \
#                --apt vlc --dnf vlc --zypper vlc --pacman vlc \
#                --arch "x86_64 aarch64"
#  Methods: flatpak | native | snap | webapp | docker | wine-bottles |
#           deb-url | github-deb | manual
#  Custom post-install commands (manifest install.postInstall) are passed as repeated
#  --post 'CMD' flags; the public install_app wrapper below runs them after a success.
# =============================================================================
_install_app_core() {
  SKIPPED_BY_USER=0   # fresh app: clear any "skip this application" from the previous one
  local name="" alt="" method="" flatpak="" snap_pkg="" arch_list="" winver="" is_security=0 is_paid=0
  local apt="" dnf="" zypper="" pacman="" launch=""
  local url_x86="" url_arm="" url_deb="" url_rpm="" webapp_url="" docker_image="" github_repo="" note="" dlpage="" script_url=""
  while [ "$#" -gt 0 ]; do
    case "$1" in
      --name)    name="$2"; shift 2 ;;
      --alt)     alt="$2"; shift 2 ;;
      --launch)  launch="$2"; shift 2 ;;
      --method)  method="$2"; shift 2 ;;
      --flatpak) flatpak="$2"; shift 2 ;;
      --snap)    snap_pkg="$2"; shift 2 ;;
      --apt)     apt="$2"; shift 2 ;;
      --dnf)     dnf="$2"; shift 2 ;;
      --zypper)  zypper="$2"; shift 2 ;;
      --pacman)  pacman="$2"; shift 2 ;;
      --arch)    arch_list="$2"; shift 2 ;;
      --winver)  winver="$2"; shift 2 ;;
      --url-x86) url_x86="$2"; shift 2 ;;
      --url-arm) url_arm="$2"; shift 2 ;;
      --url-deb) url_deb="$2"; shift 2 ;;
      --url-rpm) url_rpm="$2"; shift 2 ;;
      --webapp)  webapp_url="$2"; shift 2 ;;
      --docker)  docker_image="$2"; shift 2 ;;
      --github)  github_repo="$2"; shift 2 ;;
      --dlpage)  dlpage="$2"; shift 2 ;;
      --script-url) script_url="$2"; shift 2 ;;
      --note)     note="$2"; shift 2 ;;
      --security) is_security=1; shift ;;
      --paid)     is_paid=1; shift ;;
      *) shift ;;
    esac
  done
  [ -z "$name" ] && return 0

  # Security-suite equivalents (antivirus/firewall, etc.) are only installed when the
  # user opted in; many skip them because Linux is hardened by default.
  if [ "$is_security" -eq 1 ] && [ "${MIGRATE_INSTALL_SECURITY:-no}" != "yes" ]; then
    mark_skip "${alt:-$name}" "security suite - not installed (opted out)"
    return 0
  fi

  # Dry-run (report only): print the plan for this app and make no changes.
  if is_dry_run; then
    if ! arch_supported "$arch_list"; then mark_skip "${alt:-$name}" "not available for $ARCH"; return 0; fi
    local dpkg="" plan=""
    case "$PM" in apt) dpkg="$apt" ;; dnf) dpkg="$dnf" ;; zypper) dpkg="$zypper" ;; pacman) dpkg="$pacman" ;; esac
    case "$method" in
      webapp)       plan="web-app shortcut -> $webapp_url" ;;
      docker)       plan="docker container: $docker_image" ;;
      wine-bottles) plan="Bottles (flatpak) for a Windows app" ;;
      script)       plan="vendor install script -> $script_url" ;;
      manual)       plan="manual download-by-user" ;;
      *)
        if   [ -n "$flatpak" ];                          then plan="flatpak $flatpak"
        elif [ -n "$dpkg" ];                             then plan="native ($PM) $dpkg"
        elif [ -n "$snap_pkg" ];                         then plan="snap $snap_pkg"
        elif [ -n "$url_x86$url_arm$url_deb$url_rpm" ];   then plan="direct download"
        else plan="no automatic route -> manual"; fi ;;
    esac
    [ "$is_paid" -eq 1 ] && plan="$plan (paid)"
    mark_plan "${alt:-$name}" "$plan"
    return 0
  fi

  # Free-only mode: this app's only alternative is paid. Ask whether to proceed.
  if [ "${MIGRATE_FREE_ONLY:-no}" = "yes" ] && [ "$is_paid" -eq 1 ]; then
    local _fans=""
    if [ -r /dev/tty ]; then
      printf '\n\n\033[1;33m==> %s%s has no free alternative.\033[0m\n' "$name" "${alt:+ ---> $alt}" >&3
      printf '  No free alternative exists for this application. Do you want to continue with the installation of the paid one? Answering with No means skipping this application (y/n): ' > /dev/tty
      read -r _fans < /dev/tty || _fans="n"
      case "$_fans" in [Yy]*) ;; *) mark_skip "${alt:-$name}" "paid - skipped (free-only mode)"; return 0 ;; esac
    else
      mark_skip "${alt:-$name}" "paid - skipped (free-only mode)"; return 0
    fi
  fi

  if ! arch_supported "$arch_list"; then
    mark_skip "${alt:-$name}" "not available for $ARCH"
    return 0
  fi

  if [ -n "$alt" ]; then
    printf '\n\n\033[1;34m==> Installing: %s   --->   %s\033[0m\n' "$name" "$alt" >&3
  else
    printf '\n\n\033[1;34m==> Installing: %s\033[0m\n' "$name" >&3
  fi
  [ -n "$note" ] && info "$note"

  # native package name for the running family
  local native_pkg=""
  case "$PM" in
    apt) native_pkg="$apt" ;; dnf) native_pkg="$dnf" ;;
    zypper) native_pkg="$zypper" ;; pacman) native_pkg="$pacman" ;;
  esac
  local slug; slug="$(slugify "$name")"

  # ---- single-path methods ----
  case "$method" in
    webapp)
      webapp_desktop "$name" "$webapp_url" "$alt" "$launch"; return 0 ;;
    script)
      # Vendor's official install script (e.g. Ollama: curl -fsSL https://ollama.com/install.sh | sh).
      # Downloaded first (so an HTML/error page is never piped to a shell), then run as root.
      if [ -z "$script_url" ]; then mark_manual "${alt:-$name}" "${note:-no install-script URL provided}"; return 0; fi
      info "installing $name via its official install script ($script_url) ..."
      local stmp; stmp="$(mktemp 2>/dev/null || echo /tmp/mtl_script.$$)"
      if capture download_file "$script_url" "$stmp" && capture sh "$stmp"; then
        ledger_add script "${alt:-$name} -- uninstall per the vendor's docs (e.g. ollama: sudo systemctl disable --now ollama; sudo rm -f /usr/local/bin/ollama)"
        mark_ok "$name" "installed via the official script ($script_url)" "$alt" "$launch"
      elif user_skipped; then
        mark_skip "${alt:-$name}" "skipped by user ($SKIP_KEY_LABEL)"
      else
        mark_fail "${alt:-$name}" "${LAST_ERR:-install script failed}"
      fi
      rm -f "$stmp" 2>/dev/null || true
      return 0 ;;
    wine-bottles)
      if ensure_flatpak && capture install_flatpak com.usebottles.bottles; then
        mark_ok "$name" "via Bottles (flatpak) - configure the Windows app inside Bottles"
      else mark_fail "$name" "${LAST_ERR:-could not install Bottles (flatpak)}"; fi
      return 0 ;;
    manual)
      local mdir="${MIGRATE_MANUAL_DIR:-$DOWNLOAD_DIR/manual}/$slug" mf got=0
      if [ -d "$mdir" ] && [ -n "$(ls -A "$mdir" 2>/dev/null)" ]; then
        for mf in "$mdir"/*; do [ -f "$mf" ] && install_by_ext "$mf" && got=1; done
        if [ "$got" -eq 1 ]; then ledger_add file "$mdir"; mark_ok "$name" "installed from staged file" "$alt" "$launch"
        else mark_fail "${alt:-$name}" "${LAST_ERR:-staged file could not be installed}"; fi
      else
        mark_manual "${alt:-$name}" "${note:-manual install}"
      fi
      return 0 ;;
  esac

  # Universal "already installed" short-circuit. Unless the user asked to update
  # existing apps to the LATEST version, an app that is already present is skipped
  # entirely here -- BEFORE any vendor repo setup or download happens. This applies
  # when "same version" was chosen OR when existing apps are not being updated.
  if [ "${MIGRATE_VERSION_MODE:-latest}" = "same" ] || [ "${MIGRATE_UPDATE_EXISTING:-no}" != "yes" ]; then
    if { [ -n "$native_pkg" ] && pm_installed "${native_pkg%% *}"; } \
       || { [ -n "$flatpak" ] && have_cmd flatpak && flatpak_installed "$flatpak"; } \
       || { [ -n "$snap_pkg" ] && have_cmd snap && snap list "${snap_pkg%% *}" >/dev/null 2>&1; }; then
      local _d=""
      if   [ -n "$flatpak" ] && have_cmd flatpak && flatpak_installed "$flatpak"; then _d="flatpak $flatpak"
      elif [ -n "$native_pkg" ] && pm_installed "${native_pkg%% *}"; then _d="native $native_pkg"
      elif [ -n "$snap_pkg" ]; then _d="snap $snap_pkg"; fi
      # Show the Linux alternative (what is actually installed), not the Windows name.
      mark_skip "${alt:-$name}" "already installed" "${launch:-$(launch_hint_from_detail "${alt:-$name}" "$_d")}" "$alt"
      return 0
    fi
  fi

  # ---- multi-backend methods (req: try every available pm until one works) ----
  # The declared method goes first; then EVERY other available backend is tried as a
  # fallback (native / flatpak / snap / direct-download) before the app is failed.
  # docker is always LAST: a container is only deployed when the alternative has no
  # package-manager/binary route at all (native install is preferred over docker -- e.g.
  # Stirling-PDF ships both, so the native package wins and docker is never considered).
  local order
  case "$method" in
    flatpak)            order="flatpak native snap deburl docker" ;;
    native)             order="native flatpak snap deburl docker" ;;
    snap)               order="snap flatpak native deburl docker" ;;
    deb-url|github-deb) order="deburl native flatpak snap docker" ;;
    docker)             order="native flatpak snap deburl docker" ;;
    *)                  order="flatpak native snap deburl docker" ;;
  esac

  local b url f rfn
  LAST_ERR=""   # so an empty value after the loop means "nothing was even attempted"
  for b in $order; do
    # User skipped this app during an earlier backend: stop before any further
    # vendor-repo setup / refresh, and fall through to the "skipped" verdict.
    user_skipped && break
    case "$b" in
      flatpak)
        [ -n "$flatpak" ] || continue
        ensure_flatpak || continue
        if capture install_flatpak "$flatpak"; then finish_install "$name" "$alt" flatpak "$flatpak" "flatpak $flatpak" "$launch"; return 0; fi ;;
      native)
        [ -n "$native_pkg" ] || continue
        # vendor's own repo first, for the latest upstream build (if defined).
        rfn="repo_setup_$(printf '%s' "$slug" | tr '-' '_')"
        if declare -F "$rfn" >/dev/null 2>&1; then
          info "configuring vendor repository for $name ..."
          "$rfn" || warn "vendor repo setup failed; falling back to the distro repo"
        fi
        pm_refresh
        # Skip if present, UNLESS the user asked to update existing apps (then
        # pm_install upgrades it to the latest available).
        if pm_installed "${native_pkg%% *}" && [ "${MIGRATE_UPDATE_EXISTING:-no}" != "yes" ]; then
          mark_skip "${alt:-$name}" "already installed" "${launch:-$(launch_hint_from_detail "${alt:-$name}" "native $native_pkg")}" "$alt"; return 0
        fi
        # match the Windows version when the user chose "same version".
        if [ "${MIGRATE_VERSION_MODE:-latest}" = "same" ] && [ -n "$winver" ]; then
          if install_native_version "$native_pkg" "$winver"; then finish_install "$name" "$alt" native "$native_pkg" "native $native_pkg (matched Windows $winver)" "$launch"; return 0; fi
          warn "could not match Windows version $winver; installing latest"
        fi
        if capture pm_install $native_pkg; then finish_install "$name" "$alt" native "$native_pkg" "native $native_pkg" "$launch"; return 0; fi ;;
      snap)
        [ -n "$snap_pkg" ] || continue
        ensure_snap || continue
        if capture snap install $snap_pkg; then finish_install "$name" "$alt" snap "$snap_pkg" "snap $snap_pkg" "$launch"; return 0; fi ;;
      deburl)
        [ -n "$url_x86$url_arm$url_deb$url_rpm" ] || continue
        # Prefer the package format matching the distro family (.deb on apt, .rpm on
        # dnf/zypper); fall back to the arch-keyed URLs when no format-specific one fits.
        url=""
        case "$PM" in apt) url="$url_deb" ;; dnf|zypper) url="$url_rpm" ;; esac
        [ -n "$url" ] || { url="$url_x86"; [ "$ARCH" = "aarch64" ] && [ -n "$url_arm" ] && url="$url_arm"; }
        [ -n "$url" ] || continue
        f="$DOWNLOAD_DIR/${name// /_}.pkg"
        if capture download_file "$url" "$f" && capture install_local_package "$f"; then finish_install "$name" "$alt" file "$f" "downloaded package" "$launch"; return 0; fi ;;
      docker)
        [ -n "$docker_image" ] || continue
        # only when NO package-manager/binary route exists for this alt (native preferred).
        [ -n "$flatpak$native_pkg$snap_pkg$url_x86$url_arm$url_deb$url_rpm" ] && continue
        docker_launch_app "$name" "$docker_image" "$note"; return 0 ;;
    esac
  done

  # Package managers are first priority; the saved download page is the next priority.
  # So whether a package-manager backend FAILED or nothing was even attempted (no route
  # on this distro), fall through to the download-page stage: open the saved download URL
  # (health-checked) -- or a web search if it is missing/broken -- and let the user supply
  # the installer. The preferred page is the manifest download page (--dlpage); fall back
  # to any direct/webapp/github URL the app carried.
  # User pressed the skip key during one of the attempts above: record the app as
  # skipped (not failed) and move on -- no download-page fallback for a deliberate skip.
  if user_skipped; then
    mark_skip "${alt:-$name}" "skipped by user ($SKIP_KEY_LABEL)"
    return 0
  fi
  if [ -n "$LAST_ERR" ]; then
    warn "package-manager install failed: $LAST_ERR"
    info "falling back to the download page for $name ..."
  else
    err "no available package manager could install it"
  fi
  manual_fallback "$name" "$alt" "$note" "${dlpage:-$webapp_url$url_x86$github_repo}" "$launch"
}

# Public entry point. Pulls out any --post 'CMD' flags (custom commands to run right after
# this app installs), delegates the install to _install_app_core, then -- ONLY if the app
# was freshly installed this run (a new OK was recorded) -- runs those commands as the
# logged-in user. Everything else is unchanged, so apps without postInstall behave exactly
# as before.
install_app() {
  local -a _post=() _args=()
  local _name=""
  while [ "$#" -gt 0 ]; do
    if [ "$1" = "--post" ]; then _post+=("$2"); shift 2; continue; fi
    [ "$1" = "--name" ] && _name="$2"
    _args+=("$1"); shift
  done
  local _ok_before=${#OK_LIST[@]}
  _install_app_core "${_args[@]}"
  if [ "${#_post[@]}" -gt 0 ] && [ "${#OK_LIST[@]}" -gt "$_ok_before" ]; then
    run_post_install "$_name" "${_post[@]}"
  fi
}

# Resolve a user-typed installer path: strip surrounding single/double quotes and
# outer whitespace; absolute paths and ~/... are used as-is; a bare/relative path is
# taken relative to the logged-in user's Downloads folder. Echoes the resolved path.
resolve_user_path() {  # resolve_user_path RAW
  local p="$1"
  p="${p#"${p%%[![:space:]]*}"}"; p="${p%"${p##*[![:space:]]}"}"   # trim outer whitespace
  case "$p" in
    \'*\') p="${p#\'}"; p="${p%\'}" ;;
    \"*\") p="${p#\"}"; p="${p%\"}" ;;
  esac
  case "$p" in
    '')    : ;;
    /*)    : ;;
    '~')   p="$TARGET_HOME" ;;
    '~/'*) p="$TARGET_HOME/${p#\~/}" ;;
    *)     p="$TARGET_HOME/Downloads/$p" ;;
  esac
  printf '%s' "$p"
}

# Run a wine (Windows emulator) command as the logged-in user, in the prefix named by
# $WINE_PREFIX_DIR (a per-app prefix; defaults to the shared ~/.wine). The installer
# itself usually runs as root under sudo.
run_wine() {  # run_wine CMD [ARGS...]
  local prefix="${WINE_PREFIX_DIR:-$TARGET_HOME/.wine}"
  if [ "$(id -u)" -eq 0 ] && [ "$TARGET_USER" != "root" ]; then
    sudo -u "$TARGET_USER" env HOME="$TARGET_HOME" WINEARCH="${WINE_ARCH:-win64}" WINEPREFIX="$prefix" WINEDEBUG=-all "$@"
  else
    env HOME="$TARGET_HOME" WINEARCH="${WINE_ARCH:-win64}" WINEPREFIX="$prefix" WINEDEBUG=-all "$@"
  fi
}

# Like run_wine, but also forwards the desktop session (DISPLAY / WAYLAND_DISPLAY /
# XAUTHORITY) so a wine GUI window actually shows up on screen -- used to LAUNCH an app
# for the interactive first-launch appearance test. Registry/wineserver work that needs
# no display keeps using plain run_wine.
run_wine_gui() {  # run_wine_gui CMD [ARGS...]
  local prefix="${WINE_PREFIX_DIR:-$TARGET_HOME/.wine}"
  local disp="${DISPLAY:-:0}" xauth="${XAUTHORITY:-$TARGET_HOME/.Xauthority}" wld="${WAYLAND_DISPLAY:-}"
  if [ "$(id -u)" -eq 0 ] && [ "$TARGET_USER" != "root" ]; then
    sudo -u "$TARGET_USER" env HOME="$TARGET_HOME" WINEARCH="${WINE_ARCH:-win64}" WINEPREFIX="$prefix" WINEDEBUG=-all \
      DISPLAY="$disp" XAUTHORITY="$xauth" ${wld:+WAYLAND_DISPLAY="$wld"} "$@"
  else
    env HOME="$TARGET_HOME" WINEARCH="${WINE_ARCH:-win64}" WINEPREFIX="$prefix" WINEDEBUG=-all \
      DISPLAY="$disp" XAUTHORITY="$xauth" ${wld:+WAYLAND_DISPLAY="$wld"} "$@"
  fi
}

# Ensure wine (the Windows emulator) is installed -- and, if the user opted to update
# existing apps, up to date. Only ever called when a wine install is actually needed
# (from wine_app), and it does its package work at most once per run.
ensure_wine() {
  [ "${_WINE_READY:-0}" = "1" ] && return 0
  if have_cmd wine; then
    if [ "${MIGRATE_UPDATE_EXISTING:-no}" = "yes" ]; then
      info "updating wine (Windows emulator) ..."
      case "$PM" in
        apt) capture pm_install wine64 wine32 || capture pm_install wine || true ;;
        *)   capture pm_install wine || true ;;
      esac
    fi
    _WINE_READY=1; return 0
  fi
  info "installing wine (Windows emulator) ..."
  case "$PM" in
    apt)    dpkg --add-architecture i386 2>/dev/null || true; pm_refresh; capture pm_install wine64 wine32 || capture pm_install wine ;;
    dnf)    capture pm_install wine ;;
    zypper) capture pm_install wine ;;
    pacman) capture pm_install wine ;;
  esac
  if have_cmd wine; then _WINE_READY=1; return 0; else return 1; fi
}

# Ensure 32-bit (i386 / WoW64) wine support, required to run 32-bit Windows installers.
# A 64-bit-only wine cannot load syswow64\ntdll.dll (error c0000135). Done at most once.
ensure_wine_i386() {
  [ "${_WINE_I386_READY:-0}" = "1" ] && return 0
  info "ensuring 32-bit (i386) wine (Windows emulator) support ..."
  case "$PM" in
    apt)    dpkg --add-architecture i386 2>/dev/null || true; pm_refresh
            capture pm_install wine32:i386 || capture pm_install wine32 || capture pm_install libwine:i386 || true ;;
    dnf)    capture pm_install wine.i686 || capture pm_install wine || true ;;
    zypper) capture pm_install wine-32bit || capture pm_install wine || true ;;
    pacman) capture pm_install lib32-wine || warn "enable the [multilib] repo for 32-bit wine on Arch" ;;
  esac
  _WINE_I386_READY=1
}

# True if the installer FILE targets 32-bit x86 and therefore needs WoW64 / wine32 (a
# 64-bit-only wine fails with c0000135 -- "could not load kernel32.dll" -- on it).
# Handles BOTH PE executables (.exe) and Windows Installer (.msi) packages. An MSI is an
# OLE compound document, not a PE file, so its target CPU is read from the "Template"
# summary field: Intel -> 32-bit; x64/Intel64/Arm/Arm64 -> not 32-bit x86. MSIs with no
# recognisable arch default to "needs wine32" (the safe choice: wine32 never hurts 64-bit
# apps, but its absence breaks 32-bit ones).
is_32bit_pe() {  # is_32bit_pe FILE
  have_cmd file || return 1
  local t; t="$(file -bL "$1" 2>/dev/null)"
  case "$t" in
    *MSI\ Installer*)
      case "$t" in
        *Template:\ x64*|*Template:\ Intel64*|*Template:\ Arm*) return 1 ;;
        *)                                                      return 0 ;;
      esac ;;
    *x86-64*|*x86_64*|*PE32+*|*aarch64*|*ARM*) return 1 ;;
    *80386*|*"Intel i386"*)                    return 0 ;;
    *)                                         return 1 ;;
  esac
}

# Best-effort install of winetricks (helper for wine fonts/runtime verbs).
ensure_winetricks() {
  have_cmd winetricks && return 0
  case "$PM" in
    apt)    capture pm_install winetricks ;;
    dnf)    capture pm_install winetricks ;;
    zypper) capture pm_install winetricks ;;
    pacman) capture pm_install winetricks ;;
  esac
  have_cmd winetricks
}

# Run the Windows installer at PATH under wine, best-effort silent for the common
# installer types. Output is written to LOG (shown afterwards) -- deliberately NOT through
# a live "tee" pipe. Many installers AUTO-LAUNCH the application (or leave a tray icon /
# updater) the moment they finish; a launched process inherits the console pipe and holds
# it open, which would block the pipeline and HANG the whole script. So we run the
# installer in the background, wait for it to finish on its own (bounded by
# MIGRATE_WINE_INSTALL_TIMEOUT, default 600s), then "wineserver -k" to terminate every
# remaining Windows process in this (isolated, per-app) prefix -- so wine fully exits, the
# prefix is left idle, and the script continues. Killing the prefix between installs also
# clears any msiexec mutex, so wine never reports "another setup is already running".
# Returns wine's own exit status. Factored out so the install can be retried after
# enabling 32-bit (WoW64) wine support.
wine_run_installer() {  # wine_run_installer PATH LOG
  local p="$1" log="$2" rc to="${MIGRATE_WINE_INSTALL_TIMEOUT:-600}" waited=0 wpid
  (
    case "$p" in
      *.msi|*.MSI)             run_wine wine msiexec /i "$p" /qn ;;
      *.bat|*.BAT|*.cmd|*.CMD) run_wine wine cmd /c "$p" ;;
      *)                       run_wine wine "$p" /S ;;
    esac
  ) > "$log" 2>&1 &
  wpid=$!
  # Wait for the installer process to exit on its own, up to the timeout.
  while kill -0 "$wpid" 2>/dev/null && [ "$waited" -lt "$to" ]; do sleep 2; waited=$((waited+2)); done
  if kill -0 "$wpid" 2>/dev/null; then
    warn "the installer is still busy after ${to}s -- terminating wine so the script can continue (the app was most likely installed)."
    run_wine wineserver -k >/dev/null 2>&1 || true
  fi
  wait "$wpid" 2>/dev/null; rc=$?
  # Terminate anything the installer auto-launched (the app itself, a tray icon, an
  # updater) so the prefix is idle and wine has fully exited before we move on.
  run_wine wineserver -k >/dev/null 2>&1 || true
  cat "$log" >&3 2>/dev/null || true
  return "$rc"
}

# After a wine install, scan the per-app prefix for Start Menu .lnk shortcuts and emit
# .desktop launchers (run via "wine start") into the user's applications directory.
wine_make_launchers() {  # wine_make_launchers NAME PREFIX SLUG
  local name="$1" prefix="$2" slug="$3" appdir="$TARGET_HOME/.local/share/applications" lnk base dn n=0
  [ -d "$prefix/drive_c" ] || return 0
  mkdir -p "$appdir"
  while IFS= read -r lnk; do
    [ -f "$lnk" ] || continue
    base="$(basename "$lnk" .lnk)"
    dn="$appdir/wine-${slug}-$(printf '%s' "$base" | tr '[:upper:] ' '[:lower:]-' | tr -cd 'a-z0-9-_').desktop"
    {
      printf '[Desktop Entry]\n'
      printf 'Type=Application\n'
      printf 'Name=%s (wine - Windows emulator)\n' "$base"
      printf 'Exec=env WINEPREFIX="%s" wine start /unix "%s"\n' "$prefix" "$lnk"
      printf 'Terminal=false\nCategories=Wine;\n'
    } > "$dn" 2>/dev/null || continue
    chown "$TARGET_USER":"$TARGET_USER" "$dn" 2>/dev/null || true
    chmod +x "$dn" 2>/dev/null || true
    n=$((n+1))
  done <<EOF
$(find "$prefix/drive_c" -iname '*.lnk' -ipath '*Start Menu*' 2>/dev/null)
EOF
  [ "$n" -gt 0 ] && info "created $n wine (Windows emulator) launcher(s) for $name"
  return 0
}

# Manual download-by-user fallback for an app no package manager could install.
# Asks the user to download the installer and type its path (full, or relative to the
# logged-in user's Downloads folder) in single quotes; installs it by extension; loops
# until a valid path is given or the user skips. Marks the result.
manual_fallback() {  # manual_fallback NAME [ALT] [NOTE] [URL] [LAUNCH]
  local name="$1" alt="$2" mnote="$3" murl="$4" mlaunch="${5:-}"
  # "skip all" chosen earlier: skip this and every remaining manual app without prompting.
  if [ "${MANUAL_FALLBACK_SKIP_ALL:-0}" = "1" ]; then mark_skip "${alt:-$name}" "user skipped (skip all)"; return 0; fi
  if is_dry_run; then mark_plan "${alt:-$name}" "manual installer (you would provide its path)"; return 0; fi
  local ans f disp="${alt:-$name}"
  [ -n "$mnote" ] && info "$mnote"
  # Download-page stage: health-check the saved URL and open it, else fall back to a search.
  open_download_page "$disp" "$murl"
  info "Download the installer yourself (unzip it first if it is zipped)."
  info "Then type its path in single quotes -- either a full path, or one relative to ${TARGET_HOME}/Downloads."
  info "Any valid installer extension works (.deb/.rpm/.sh/.run/.bin/.bundle/.AppImage/.tar.gz/.zip/...); 'skip' to skip this app, or 'skip all' to skip this and every remaining manual app."
  if [ ! -r /dev/tty ]; then mark_manual "${alt:-$name}" "no package manager route - needs manual download"; return 0; fi
  while :; do
    printf "  %s ('installer path'/s=skip/a=skip all): " "$disp" > /dev/tty
    read -r ans < /dev/tty || ans="skip"
    case "$ans" in
      [Aa]|[Aa][Ll][Ll]|[Ss][Kk][Ii][Pp][Aa][Ll][Ll]|'skip all'|'Skip all'|'Skip All'|'SKIP ALL')
        MANUAL_FALLBACK_SKIP_ALL=1; mark_skip "${alt:-$name}" "user skipped (skip all)"; return 0 ;;
      [Ss]|[Ss][Kk][Ii][Pp]) mark_skip "${alt:-$name}" "user skipped"; return 0 ;;
      *)
        f="$(resolve_user_path "$ans")"
        if [ -z "$f" ] || [ ! -f "$f" ] || [ ! -r "$f" ]; then
          printf "\033[1;31m  No readable file at that path -- type the path in single quotes (e.g. '%s/Downloads/app.deb'), or skip.\033[0m\n" "$TARGET_HOME" > /dev/tty; continue
        fi
        LAST_ERR=""
        if install_by_ext "$f"; then ledger_add file "$f"; mark_ok "$name" "installed from $f" "$alt" "$mlaunch"; return 0
        else printf "\033[1;31m  %s -- fix the file and re-enter its path, or skip.\033[0m\n" "${LAST_ERR:-could not handle the file}" > /dev/tty; fi
        ;;
    esac
  done
}

# --------------------- wine first-launch appearance tuning -------------------
# The adjustable visual factors and the "current" value that reproduces the
# appearance the freshly-installed app already has (font/DPI starts at 2.5x = 240,
# no virtual desktop). Once the user picks "yes all" these remembered values are
# applied silently to every later wine install. Defaults are seeded lazily.
: "${WINE_CFG_DPI:=240}"          # font scaling (DPI); 96 = 1x, 240 = 2.5x
: "${WINE_CFG_DESKTOP:=off}"      # virtual desktop size "WxH", or "off" for native windows
: "${WINE_APPEARANCE_ALL:=0}"     # 1 once the user answered "a" (apply to all upcoming)

# Pick the most likely "main program" Start Menu .lnk to launch for the test run
# (skip uninstallers / readmes / help / website links).
wine_primary_lnk() {  # wine_primary_lnk PREFIX
  local prefix="$1"
  [ -d "$prefix/drive_c" ] || return 1
  find "$prefix/drive_c" -iname '*.lnk' -ipath '*Start Menu*' 2>/dev/null \
    | grep -viE 'uninstall|readme|help|website|home page|homepage|on the web|manual' \
    | head -n1
}

# Heuristic: did SOMETHING actually get installed into this prefix? Used to rescue installs
# whose installer crashed on a final step (very common under wine -- a failed HTML/Gecko ad
# pane, a "run now" step, etc.) AFTER the program's files were already written. Evidence:
# a real Start-Menu shortcut, OR an application folder under Program Files / a per-user app
# data folder beyond the empty wine defaults.
wine_app_installed() {  # wine_app_installed PREFIX
  local prefix="$1" d base
  [ -d "$prefix/drive_c" ] || return 1
  [ -n "$(wine_primary_lnk "$prefix" 2>/dev/null)" ] && return 0
  while IFS= read -r d; do
    [ -n "$d" ] || continue
    base="$(basename "$d")"
    case "$base" in
      'Common Files'|'Internet Explorer'|'Windows Media Player'|'Windows NT'|'Windows Mail'|\
      'Windows Photo Viewer'|'Windows Sidebar'|'Microsoft.NET'|'Uninstall Information'|'desktop.ini') continue ;;
      *) return 0 ;;
    esac
  done <<EOF
$(find "$prefix"/drive_c/Program\ Files "$prefix"/drive_c/Program\ Files\ \(x86\) -maxdepth 1 -mindepth 1 -type d 2>/dev/null)
EOF
  return 1
}

# Launch the app (non-blocking) so its window appears on the user's desktop.
wine_launch() {  # wine_launch PREFIX LNK
  local prefix="$1" lnk="$2"
  WINE_PREFIX_DIR="$prefix"
  [ -n "$lnk" ] || { warn "no Start Menu shortcut found to launch for the test -- skipping the live preview"; return 1; }
  ( run_wine_gui wine start /unix "$lnk" >/dev/null 2>&1 & ) >/dev/null 2>&1
  sleep 3   # give the window a moment to draw before we ask about its appearance
  return 0
}

# Close every wine process in the prefix (used between/after appearance changes).
wine_close() {  # wine_close PREFIX
  local prefix="$1"; WINE_PREFIX_DIR="$prefix"
  run_wine wineserver -k >/dev/null 2>&1 || true
  sleep 1
}

# Validate the adjustable factors the user types.
valid_wine_dpi() {  # whole number 96..480
  case "$1" in ''|*[!0-9]*) return 1 ;; esac
  [ "$1" -ge 96 ] && [ "$1" -le 480 ]
}
# Accepts (W,H) / W,H / WxH (W,H positive), or off/native/none/no -> echoes WxH or "off".
normalize_wine_desktop() {  # normalize_wine_desktop INPUT  (echoes normalized, or nothing if invalid)
  local v="$1" w h
  v="$(printf '%s' "$v" | tr -d '[:space:]()')"
  case "$v" in
    [Oo][Ff][Ff]|[Nn][Oo]|[Nn][Oo][Nn][Ee]|[Nn][Aa][Tt][Ii][Vv][Ee]) printf 'off'; return 0 ;;
  esac
  v="$(printf '%s' "$v" | tr 'X' 'x')"
  case "$v" in
    *,*) w="${v%%,*}"; h="${v##*,}" ;;
    *x*) w="${v%%x*}"; h="${v##*x}" ;;
    *)   return 1 ;;
  esac
  case "$w" in ''|*[!0-9]*) return 1 ;; esac
  case "$h" in ''|*[!0-9]*) return 1 ;; esac
  [ "$w" -ge 320 ] && [ "$h" -ge 240 ] || return 1
  printf '%sx%s' "$w" "$h"
}

# Apply the current WINE_CFG_* factors to a prefix (font DPI + virtual desktop).
wine_apply_appearance() {  # wine_apply_appearance PREFIX
  local prefix="$1" hex; WINE_PREFIX_DIR="$prefix"
  hex="$(printf '0x%08X' "${WINE_CFG_DPI:-240}")"
  run_wine wine reg add 'HKEY_CURRENT_USER\Control Panel\Desktop' /v LogPixels /t REG_DWORD /d "$hex" /f >/dev/null 2>&1 || true
  if [ -n "${WINE_CFG_DESKTOP:-}" ] && [ "${WINE_CFG_DESKTOP}" != "off" ]; then
    run_wine wine reg add 'HKEY_CURRENT_USER\Software\Wine\Explorer\Desktops' /v Default /t REG_SZ /d "${WINE_CFG_DESKTOP}" /f >/dev/null 2>&1 || true
    run_wine wine reg add 'HKEY_CURRENT_USER\Software\Wine\Explorer'          /v Desktop /t REG_SZ /d Default            /f >/dev/null 2>&1 || true
  else
    run_wine wine reg delete 'HKEY_CURRENT_USER\Software\Wine\Explorer' /v Desktop /f >/dev/null 2>&1 || true
  fi
}

# Collect new values for every adjustable factor (each its own validate-or-retry loop).
# Updates WINE_CFG_DPI / WINE_CFG_DESKTOP. Empty input leaves a factor unchanged.
wine_collect_factors() {
  local ans norm
  # --- font scaling (DPI) ---
  while :; do
    printf '  enter new value for font scaling (DPI) in the format <a whole number 96-480, e.g. 96/120/144/192/240> (Current:%s) or enter to leave it unchanged: ' "${WINE_CFG_DPI:-240}" > /dev/tty
    read -r ans < /dev/tty || ans=""
    [ -z "$ans" ] && break
    if valid_wine_dpi "$ans"; then WINE_CFG_DPI="$ans"; break
    else printf '\033[1;31m  Invalid font scaling -- enter a whole number between 96 and 480 (96 = normal, 240 = 2.5x).\033[0m\n' > /dev/tty; fi
  done
  # --- window size (virtual desktop) ---
  while :; do
    printf '  enter new value for window size in the format <(width,height), e.g. (1024,768), or "off" for the app to use its own windows> (Current:%s) or enter to leave it unchanged: ' "${WINE_CFG_DESKTOP:-off}" > /dev/tty
    read -r ans < /dev/tty || ans=""
    [ -z "$ans" ] && break
    norm="$(normalize_wine_desktop "$ans")"
    if [ -n "$norm" ]; then WINE_CFG_DESKTOP="$norm"; break
    else printf '\033[1;31m  Invalid window size -- use (width,height) with width>=320 and height>=240 (e.g. (1280,720)), or "off".\033[0m\n' > /dev/tty; fi
  done
}

# Interactive first-launch appearance tuning for a freshly-installed wine app. Launches
# the app so the user can see it, collects/validates new visual-factor values, applies
# them, relaunches, and confirms -- with "start over" (r), "yes" (y) and "yes all" (a,
# remembered for every later wine install). No tty -> leave the defaults already applied.
wine_tune_appearance() {  # wine_tune_appearance NAME PREFIX
  local name="$1" prefix="$2" lnk ans
  WINE_PREFIX_DIR="$prefix"
  [ -r /dev/tty ] || return 0
  lnk="$(wine_primary_lnk "$prefix")"
  # "yes all" chosen earlier: apply the remembered look silently, no launch/prompting.
  if [ "${WINE_APPEARANCE_ALL:-0}" = "1" ]; then
    wine_apply_appearance "$prefix"
    info "applied your saved wine appearance (font DPI ${WINE_CFG_DPI:-240}, window ${WINE_CFG_DESKTOP:-off}) to $name"
    return 0
  fi
  # This app was just installed with the baseline look (DPI 240, native windows), so the
  # "Current:" shown for each factor must reflect that baseline.
  WINE_CFG_DPI=240; WINE_CFG_DESKTOP=off
  # one empty line after the last install line, then the purple launch notice.
  printf '\n' >&3
  purple "Now we launch the installed $name for the first time for testing"
  wine_launch "$prefix" "$lnk"
  while :; do   # start-over loop: broken only by "yes" (y) or "yes all" (a)
    purple "According to what you see for the appearance of the app, adjust the following visual settings or press enter to leave the default values:"
    wine_collect_factors
    # close, apply the chosen factors, then relaunch so the user sees the result.
    wine_close "$prefix"
    wine_apply_appearance "$prefix"
    wine_launch "$prefix" "$lnk"
    while :; do
      purple 'Is the current appearance what you would expect? "a" applies same configurations to all upcoming wine installations. (y=yes / a=yes all / r=start over)'
      printf '  (y/a/r): ' > /dev/tty
      read -r ans < /dev/tty || ans="y"
      case "$ans" in
        [Yy]|[Yy][Ee][Ss]) wine_close "$prefix"; return 0 ;;
        [Aa]|[Aa][Ll][Ll]) WINE_APPEARANCE_ALL=1; wine_close "$prefix"; info "these appearance settings will be applied to all upcoming wine installations"; return 0 ;;
        [Rr]|[Rr][Ee][Ss][Tt][Aa][Rr][Tt]) break ;;   # start over -> re-collect (app stays open)
        *) printf '\033[1;31m  Please answer y (yes), a (yes all), or r (start over).\033[0m\n' > /dev/tty ;;
      esac
    done
  done
}

# Install a non-cross-platform Windows app under wine (the Windows emulator), when the
# user opted in (MIGRATE_WINE_NONCROSS=yes). Tries the manifest-provided Windows
# installer URL first; on failure (or none) asks for the installer path in single
# quotes. After installing, scales the wine font/DPI to 2.5x (LogPixels 240) so the
# app is readable. Marks the result.
wine_app() {  # wine_app NAME [WINDOWS_INSTALLER_URL] [NOT_RECOMMENDED_REASON] [RECOMMENDED_ACTION]
  [ "${MIGRATE_WINE_NONCROSS:-no}" = "yes" ] || return 0
  local name="$1" winurl="${2:-}" nrreason="${3:-}" nraction="${4:-}" ans f winpath="" slug dir rc prefix is_upgrade=0 WINE_ARCH=win64 win32_retried=0
  if [ "${WINE_SKIP_ALL:-0}" = "1" ]; then mark_skip "$name (wine - Windows emulator)" "user skipped (skip all)"; return 0; fi
  if is_dry_run; then mark_plan "$name (wine - Windows emulator)" "${nrreason:+NOT RECOMMENDED; }${winurl:+auto-download + }run under wine in a per-app prefix; font 2.5x"; return 0; fi
  printf '\n\n\033[1;34m==> Install under wine (Windows emulator): %s\033[0m\n' "$name" >&3
  if ! ensure_wine; then mark_fail "$name (wine - Windows emulator)" "${LAST_ERR:-could not install wine}"; return 0; fi
  slug="$(slugify "$name")"
  # Per-app wine prefix (isolated, so one Windows app cannot break another).
  prefix="$TARGET_HOME/.local/share/wineprefixes/$slug"; WINE_PREFIX_DIR="$prefix"
  # Handle an app that is ALREADY installed in its (persistent) per-app prefix.
  #   * not updating -> SKIP the re-install (the app is already there).
  #   * updating     -> upgrade IN PLACE: keep the prefix (and the user's data/settings),
  #                     and do NOT redo the FIRST-INSTALL appearance setup (font/DPI, virtual
  #                     desktop, the interactive tuning). Re-launching + re-applying that on
  #                     every run is what made some apps' UI grow; and an upgrade must PRESERVE
  #                     what the user already has, not reset it. So an upgrade only refreshes
  #                     the program binaries; the appearance is left exactly as it was.
  if [ -n "$(wine_primary_lnk "$prefix" 2>/dev/null)" ]; then
    if [ "${MIGRATE_UPDATE_EXISTING:-no}" != "yes" ]; then
      mark_skip "$name (wine - Windows emulator)" "already installed under wine (delete '$prefix' to reinstall)"
      return 0
    fi
    is_upgrade=1; info "upgrading $name under wine in place (keeping your data and current appearance) ..."
  fi
  mkdir -p "$prefix" && chown -R "$TARGET_USER":"$TARGET_USER" "$TARGET_HOME/.local/share/wineprefixes" 2>/dev/null || true
  dir="${MIGRATE_MANUAL_DIR:-$DOWNLOAD_DIR/manual}/wine-$slug"; mkdir -p "$dir"
  # 1) auto-download the Windows installer if the manifest provided a URL (recommended
  #    apps only -- "not recommended" apps always go to the prompt so the warning shows).
  if [ -n "$winurl" ] && [ -z "$nrreason" ]; then
    f="$dir/${slug}-setup.exe"
    info "Downloading the Windows installer for $name (to run under wine - Windows emulator) ..."
    if capture download_file "$winurl" "$f"; then winpath="$f"
    else warn "automatic download failed -- you can provide the installer yourself."; fi
  fi
  # 2) manual fallback: ask for the installer path in single quotes.
  if [ -z "$winpath" ]; then
    if [ ! -r /dev/tty ]; then mark_manual "$name (wine - Windows emulator)" "provide a Windows installer to run under wine"; return 0; fi
    # Download-page stage: health-check the saved Windows-installer URL and open it, else
    # fall back to a web search for the app's official Windows installer.
    open_download_page "$name" "$winurl" "$name Windows installer download"
    info "Download the Windows installer for $name (unzip it first if it is zipped)."
    info "Then type its path in single quotes -- either a full path, or one relative to ${TARGET_HOME}/Downloads."
    info "Any valid installer extension works (.exe, .msi, .bat, etc.); 'skip' to skip this app, or 'skip all' to skip every remaining wine (Windows emulator) install."
    [ -n "$nrreason" ] && warn "Not recommended: ${nrreason}${nraction:+  Recommended: ${nraction}}"
    while :; do
      printf "  %s ('installer path'/s=skip/a=skip all): " "$name" > /dev/tty
      read -r ans < /dev/tty || ans="skip"
      case "$ans" in
        [Aa]|[Aa][Ll][Ll]|[Ss][Kk][Ii][Pp][Aa][Ll][Ll]|'skip all'|'Skip all'|'Skip All'|'SKIP ALL')
          WINE_SKIP_ALL=1; mark_skip "$name (wine - Windows emulator)" "user skipped (skip all)"; return 0 ;;
        [Ss]|[Ss][Kk][Ii][Pp]) mark_skip "$name (wine - Windows emulator)" "user skipped"; return 0 ;;
        *)
          winpath="$(resolve_user_path "$ans")"
          if [ -n "$winpath" ] && [ -f "$winpath" ] && [ -r "$winpath" ]; then break
          else printf "\033[1;31m  No readable file at that path -- type the path in single quotes (e.g. '%s/Downloads/setup.exe'), or skip.\033[0m\n" "$TARGET_HOME" > /dev/tty; winpath=""; fi ;;
      esac
    done
  fi
  # 2b) Choose the wine prefix ARCHITECTURE before the prefix is initialised.
  #   * Upgrade in place: keep whatever arch the existing (working) prefix already is --
  #     never change it, so a working app and its data are preserved.
  #   * Fresh install of a 32-bit (i386) installer: use a 32-bit (win32) prefix. A 64-bit
  #     (win64) prefix needs functional WoW64 to load 32-bit kernel32; on several distros
  #     that fails with c0000135 even when wine32 is installed. A win32 prefix runs 32-bit
  #     apps directly. 64-bit apps keep the default win64 prefix (UNCHANGED).
  if [ "$is_upgrade" -eq 1 ]; then
    grep -q '#arch=win32' "$prefix/system.reg" 2>/dev/null && WINE_ARCH=win32
  elif is_32bit_pe "$winpath"; then
    info "installer is 32-bit (i386) -- using a 32-bit (win32) wine prefix ..."
    ensure_wine_i386; WINE_ARCH=win32
    # A leftover prefix of the wrong arch (e.g. a previous FAILED win64 attempt) cannot be
    # reused as win32. This branch is fresh-install only (no Start-Menu .lnk existed), so no
    # working app or user data is present -- safe to recreate it as win32.
    if [ -d "$prefix" ] && [ -n "$(ls -A "$prefix" 2>/dev/null)" ] && ! grep -q '#arch=win32' "$prefix/system.reg" 2>/dev/null; then
      info "removing a leftover non-32-bit wine prefix so it can be created as win32 ..."
      rm -rf "$prefix" 2>/dev/null || true; mkdir -p "$prefix"
      chown -R "$TARGET_USER":"$TARGET_USER" "$TARGET_HOME/.local/share/wineprefixes" 2>/dev/null || true
    fi
  fi
  run_wine wineboot -u >/dev/null 2>&1 || true
  # winetricks font baseline for better rendering/compatibility (best-effort).
  if ensure_winetricks; then run_wine winetricks -q corefonts >/dev/null 2>&1 || true; fi
  # 3) run the installer under wine (best-effort silent), then scale the font/DPI 2.5x.
  #    Capture wine's full output so a meaningful failure reason can be reported.
  info "installing $name under wine (Windows emulator) ..."
  info "NOTE: this install runs unattended. If the app or a 'Setup finished / Run now'"
  info "      window opens, just CLOSE that window so the installer can finish -- otherwise"
  info "      the script force-closes it automatically after a timeout and then continues."
  local wlog; wlog="$(mktemp 2>/dev/null || echo /tmp/mtl_wine.$$)"
  wine_run_installer "$winpath" "$wlog"; rc=$?
  # Self-heal the classic 32-bit bootstrap failure: wine could not load kernel32.dll
  # (c0000135) -- the 32-bit subsystem failed. This also covers an installer whose
  # 32-bit-ness we could not detect up front (e.g. no `file` command). Enable 32-bit wine,
  # fall back to a 32-bit (win32) prefix (a win64 prefix's WoW64 fails this way on some
  # distros), rebuild the (worthless, half-booted) prefix, and retry the install ONCE. Only
  # ever triggered on an install FAILURE, so there is no working app / data to lose.
  if [ "$rc" -ne 0 ] && [ "$win32_retried" != "1" ] \
     && grep -qiE 'c0000135|could not load (kernel32|ntdll)' "$wlog" 2>/dev/null; then
    warn "wine could not load kernel32 (c0000135) -- enabling 32-bit support, switching to a 32-bit (win32) prefix, and retrying ..."
    ensure_wine_i386; WINE_ARCH=win32; win32_retried=1
    rm -rf "$prefix" 2>/dev/null || true; mkdir -p "$prefix"
    chown -R "$TARGET_USER":"$TARGET_USER" "$TARGET_HOME/.local/share/wineprefixes" 2>/dev/null || true
    run_wine wineboot -u >/dev/null 2>&1 || true
    wine_run_installer "$winpath" "$wlog"; rc=$?
  fi
  # font size 2.5x: default wine DPI 96 -> 240 (LogPixels 0xF0). FIRST INSTALL ONLY -- on an
  # in-place upgrade the user's existing DPI/appearance is left untouched (never re-applied,
  # so it can never accumulate / grow).
  if [ "$is_upgrade" -eq 0 ]; then
    run_wine wine reg add 'HKEY_CURRENT_USER\Control Panel\Desktop' /v LogPixels /t REG_DWORD /d 0x000000F0 /f >/dev/null 2>&1 || true
  fi
  if [ "$rc" -eq 0 ]; then
    ledger_add wine "$prefix"
    wine_make_launchers "$name" "$prefix" "$slug"
    if [ "$is_upgrade" -eq 1 ]; then
      mark_ok "$name (wine - Windows emulator)" "upgraded under wine in place (data + appearance preserved)"
    else
      mark_ok "$name (wine - Windows emulator)" "installed under wine (per-app prefix); font/DPI 2.5x (240)"
      # First-launch appearance tuning: launch the app, let the user adjust the visual
      # factors, apply + confirm (or reuse the "yes all" settings). No-op without a tty.
      # First install ONLY -- WINE_CFG_DPI / WINE_CFG_DESKTOP / WINE_APPEARANCE_ALL and the
      # registry are never touched again on later upgrades.
      wine_tune_appearance "$name" "$prefix"
    fi
  elif wine_app_installed "$prefix"; then
    # The installer exited non-zero, but the app's files / shortcut are present: under wine an
    # installer commonly crashes on a FINAL step (a Gecko/HTML ad pane, a "run now" launch,
    # etc.) AFTER it has already installed the program. Treat that as installed-but-UNVERIFIED
    # rather than a hard failure -- still ledger it and create launchers -- so these apps are
    # not lost. (No interactive appearance tuning here: the install is already questionable;
    # the 2.5x DPI baseline set above still applies.)
    ledger_add wine "$prefix"
    wine_make_launchers "$name" "$prefix" "$slug"
    mark_unverified "$name (wine - Windows emulator)" "the installer reported an error on exit, but the app appears installed -- launch it from the menu to confirm; if it misbehaves, reinstall with:  WINEPREFIX='$prefix' wine '$winpath'"
  else
    # Surface the most informative line from wine's output (skip fixme/diag noise),
    # then explain likely causes and the exact command to reproduce it interactively.
    local wreason ftype=""
    # Prefer a specific, human-meaningful cause (missing DLL/dependency/file, exception)...
    wreason="$(grep -iE 'import_dll|Library .* not found|cannot (find|open|execute)|No such file|Unhandled exception|needs.*(mono|gecko)|vcrun|msvc|\.NET' "$wlog" 2>/dev/null | grep -viE 'fixme:' | tail -n1 | sed 's/^[[:space:]]*//')"
    # ...otherwise any other err:/wine: line, ...
    [ -z "$wreason" ] && wreason="$(grep -iE 'err:|wine:|0x[0-9A-Fa-f]{6,}' "$wlog" 2>/dev/null | grep -viE 'fixme:|err:winediag' | tail -n1 | sed 's/^[[:space:]]*//')"
    # ...otherwise the last non-empty line.
    [ -z "$wreason" ] && wreason="$(grep -v '^[[:space:]]*$' "$wlog" 2>/dev/null | tail -n1 | sed 's/^[[:space:]]*//')"
    [ -z "$wreason" ] && wreason="exit code $rc"
    have_cmd file && ftype="$(file -bL "$winpath" 2>/dev/null)"
    mark_fail "$name (wine - Windows emulator)" "$wreason${ftype:+ | file is: $ftype} | likely a missing dependency, a wrong/partial download, or no silent-install support -- reproduce + see the full error with:  WINEPREFIX='$prefix' wine '$winpath'"
  fi
  rm -f "$wlog" 2>/dev/null || true
}

# True if FLAG appears as a standalone token in the remaining args.
_args_have_flag() {  # _args_have_flag FLAG ARGS...
  local flag="$1"; shift
  while [ "$#" -gt 0 ]; do [ "$1" = "$flag" ] && return 0; shift; done
  return 1
}
# Echo the value token that follows FLAG in the remaining args (empty if absent).
_arg_val() {  # _arg_val FLAG ARGS...
  local flag="$1"; shift
  while [ "$#" -gt 0 ]; do [ "$1" = "$flag" ] && { printf '%s' "${2:-}"; return 0; }; shift; done
}
# Numeric strictly-greater test, tolerant of decimal competency values.
_comp_gt() { awk -v a="$1" -v b="$2" 'BEGIN{exit !((a+0) > (b+0))}'; }
# eval-safe quoting of a command + its args (so a buffered install can be replayed later).
_quote_cmd() { local out=""; while [ "$#" -gt 0 ]; do out="$out $(printf '%q' "$1")"; shift; done; printf '%s' "$out"; }

# -----------------------------------------------------------------------------
# Alternative deployment for one Windows app.
#   Usage:  app_alt RANK TOTAL ISNATIVE COMPETENCY install_app ...
# The user's answer to "How many best alternatives ...?" is MIGRATE_ALT_LIMIT = N, and
# it counts NATIVE installs only (appType "Native ...").  The model (alternatives arrive
# in competency-descending order, rank 1 = best):
#   1. In only-free mode, paid alternatives are dropped from consideration entirely.
#   2. The top N eligible NATIVE alternatives are installed; the lowest of them sets a
#      competency THRESHOLD.
#   3. Every eligible NON-native alternative (WebApp / Docker container) ranked ABOVE that
#      threshold is ALSO deployed (these ride along for free; they do not consume an N
#      slot).  If the app has no native alternative at all, every eligible non-native is
#      deployed (there is no native to anchor a threshold).
#   N = 0 deploys nothing.  Wine/Proton alternatives are never routed here (the separate
#   wine prompt handles them), so the generator does not emit app_alt lines for them.
# Each call buffers its alternative; the LAST one (rank == total) computes the set and
# runs the chosen installs in rank order.
app_alt() {  # app_alt RANK TOTAL ISNATIVE COMPETENCY install_app ...
  local rank="$1" total="$2" isnat="$3" comp="$4"; shift 4
  if [ "$rank" -eq 1 ]; then
    _AA_TOTAL="$total"; _AA_NAME="$(_arg_val --name "$@")"
    _AA_NAT=(); _AA_COMP=(); _AA_PAID=(); _AA_CMD=()
  fi
  _AA_NAT[$rank]="$isnat"
  _AA_COMP[$rank]="$comp"
  if _args_have_flag --paid "$@"; then _AA_PAID[$rank]=1; else _AA_PAID[$rank]=0; fi
  _AA_CMD[$rank]="$(_quote_cmd "$@")"
  [ "$rank" -ge "$total" ] && _aa_flush
  return 0
}

# Decide and run the deployment set for the app currently buffered in the _AA_* arrays.
_aa_flush() {
  local limit="${MIGRATE_ALT_LIMIT:-1}" free="${MIGRATE_FREE_ONLY:-no}"
  case "$limit" in ''|*[!0-9]*) limit=1 ;; esac
  local total="${_AA_TOTAL:-0}" r picked=0 threshold="" sawpaid=0 anydep=0
  local -a chosen=()
  # pass 1: pick the top `limit` eligible NATIVE alts; the last sets the threshold.
  for (( r=1; r<=total; r++ )); do
    if [ "$free" = yes ] && [ "${_AA_PAID[$r]:-0}" = 1 ]; then sawpaid=1; continue; fi
    if [ "${_AA_NAT[$r]:-0}" = 1 ] && [ "$picked" -lt "$limit" ]; then
      chosen[$r]=1; picked=$(( picked + 1 )); threshold="${_AA_COMP[$r]}"
    fi
  done
  # pass 2: deploy chosen natives + qualifying non-natives, in rank (competency) order.
  for (( r=1; r<=total; r++ )); do
    if [ "$free" = yes ] && [ "${_AA_PAID[$r]:-0}" = 1 ]; then continue; fi
    local dep=0
    if [ "${chosen[$r]:-0}" = 1 ]; then
      dep=1
    elif [ "${_AA_NAT[$r]:-0}" != 1 ] && [ "$limit" -ge 1 ]; then
      # non-native: deploy if it outranks the threshold, OR if no native was chosen at all.
      if [ "$picked" -eq 0 ] || _comp_gt "${_AA_COMP[$r]}" "$threshold"; then dep=1; fi
    fi
    if [ "$dep" -eq 1 ]; then eval "${_AA_CMD[$r]}"; anydep=1; fi
  done
  if [ "$anydep" -eq 0 ] && [ "$limit" -ge 1 ] && [ "$sawpaid" -eq 1 ]; then
    mark_skip "$_AA_NAME" "paid - skipped (only-free mode); no free alternative available"
  fi
}

# Handle a user-downloaded installer FILE according to its extension. Returns 0 on
# success, 1 on failure (LAST_ERR holds a 1-line reason). Used by the manual phase.
install_by_ext() {  # install_by_ext FILE
  local f="$1"
  case "$f" in
    *.deb|*.rpm|*.pkg.tar.zst|*.pkg.tar.xz|*.pkg.tar)
      capture install_local_package "$f" ;;
    *.sh)
      chmod +x "$f" 2>/dev/null; capture bash "$f" ;;
    *.run|*.bin|*.bundle)
      chmod +x "$f" 2>/dev/null; capture "$f" ;;
    *.appimage|*.AppImage)
      chmod +x "$f" 2>/dev/null
      mkdir -p /opt/migrate_appimages
      if cp -f "$f" /opt/migrate_appimages/ 2>/dev/null; then return 0
      else LAST_ERR="could not place AppImage in /opt/migrate_appimages"; return 1; fi ;;
    *.tar.gz|*.tgz|*.tar.bz2|*.tbz2|*.tar.xz|*.txz|*.tar)
      mkdir -p "${f%/*}/extracted"
      capture tar -xf "$f" -C "${f%/*}/extracted" ;;
    *.zip)
      if ! have_cmd unzip; then LAST_ERR="unzip is not installed"; return 1; fi
      mkdir -p "${f%/*}/extracted"
      capture unzip -o "$f" -d "${f%/*}/extracted" ;;
    *)
      LAST_ERR="unsupported file type: .${f##*.}"; return 1 ;;
  esac
}

ensure_docker() {
  have_cmd docker && return 0
  pm_refresh
  case "$PM" in
    apt)    pm_install docker.io ;;
    dnf)    pm_install moby-engine || pm_install docker ;;
    zypper) pm_install docker ;;
    pacman) pm_install docker ;;
  esac
  have_cmd docker && systemctl enable --now docker 2>/dev/null
  have_cmd docker
}

# =============================================================================
#  DOCKER CONTAINER LAUNCHING  (apps whose Linux equivalent IS a container)
# -----------------------------------------------------------------------------
#  For each app with install.method=docker we pull the image, attach it to ONE
#  shared bridge network, and start a container with sensible defaults. Host
#  ports are taken from the image's EXPOSED ports and bumped by 1 on conflict.
#  If a container for the same image already exists, we just (re)start it instead
#  of creating a duplicate. These are NOT the images migrated from Windows Docker
#  (those are handled separately by docker_rebuild.sh).
# =============================================================================
DOCKER_NET="${DOCKER_NET:-migrate-bridge}"

ensure_docker_net() {
  docker network inspect "$DOCKER_NET" >/dev/null 2>&1 && return 0
  capture docker network create --driver bridge "$DOCKER_NET" >/dev/null 2>&1 || \
    docker network create --driver bridge "$DOCKER_NET" >/dev/null 2>&1
}

# Track host ports assigned during this run; combined with live listener checks.
_MIGRATE_PORTS_TAKEN=""
_port_in_use() {  # _port_in_use PORT
  local p="$1"
  case " $_MIGRATE_PORTS_TAKEN " in *" $p "*) return 0 ;; esac
  if have_cmd ss; then
    ss -ltnH 2>/dev/null | awk '{print $4}' | sed 's/.*[:.]//' | grep -qx "$p" && return 0
  elif have_cmd netstat; then
    netstat -ltn 2>/dev/null | awk 'NR>2{print $4}' | sed 's/.*[:.]//' | grep -qx "$p" && return 0
  fi
  return 1
}
_pick_port() {  # _pick_port DESIRED -> free host port (incrementing on conflict)
  local p="$1"
  [ -z "$p" ] && { printf ''; return 0; }
  while _port_in_use "$p"; do p=$((p + 1)); done
  _MIGRATE_PORTS_TAKEN="$_MIGRATE_PORTS_TAKEN $p"
  printf '%s' "$p"
}

# Human-readable "how to use" line derived from the container's published ports.
_docker_howto() {  # _docker_howto CONTAINER NOTE
  local c="$1" note="$2" hp howto
  hp="$(docker port "$c" 2>/dev/null | sed -n 's/.*:\([0-9]\{1,\}\)$/\1/p' | head -n1)"
  if [ -n "$hp" ]; then howto="open http://localhost:${hp} in your browser"
  else howto="attach with: docker exec -it ${c} sh"; fi
  howto="${howto}; start/stop with: docker start ${c} / docker stop ${c}"
  [ -n "$note" ] && howto="${howto} (${note})"
  printf '%s' "$howto"
}

# Record a launched container ONCE (one line per container, deduped by name).
_record_launched() {  # _record_launched WINAPP IMAGE CONTAINER NOTE
  local winapp="$1" image="$2" c="$3" note="$4"
  if [ -f "$DOCKER_LAUNCHED" ] && cut -f3 "$DOCKER_LAUNCHED" 2>/dev/null | grep -qx "$c"; then return 0; fi
  printf '%s\t%s\t%s\t%s\n' "$winapp" "$image" "$c" "$(_docker_howto "$c" "$note")" >> "$DOCKER_LAUNCHED"
}

docker_launch_app() {  # docker_launch_app WINAPP IMAGE NOTE
  local winapp="$1" image="$2" note="$3"
  [ -z "$image" ] && { mark_fail "$winapp" "no docker image specified"; return 0; }
  if ! ensure_docker; then mark_fail "$winapp" "docker is not available"; return 0; fi
  docker info >/dev/null 2>&1 || systemctl start docker 2>/dev/null || true

  # Stable container name derived from the image (so the SAME image always maps to
  # the SAME container -> reuse instead of duplicate).
  local base cname
  base="${image##*/}"; base="${base%%:*}"
  cname="migrate-$(slugify "$base")"

  # Already created (this run or a previous one)? Just start it if stopped; never
  # create a second container for the same image.
  if docker ps -a --format '{{.Names}}' 2>/dev/null | grep -qx "$cname"; then
    if docker ps --format '{{.Names}}' 2>/dev/null | grep -qx "$cname"; then
      info "container already running: $cname"
    else
      capture docker start "$cname" >/dev/null 2>&1 || docker start "$cname" >/dev/null 2>&1 || true
    fi
    _record_launched "$winapp" "$image" "$cname" "$note"
    mark_ok "$winapp" "using existing container: $cname"
    return 0
  fi

  if ! capture docker pull "$image"; then mark_fail "$winapp" "${LAST_ERR:-could not pull docker image $image}"; return 0; fi
  ensure_docker_net

  # Map each EXPOSED container port to a free host port (incrementing on conflict).
  local pflags="" ep cport hport
  for ep in $(docker image inspect --format '{{range $p,$_ := .Config.ExposedPorts}}{{$p}} {{end}}' "$image" 2>/dev/null); do
    cport="${ep%%/*}"
    [ -z "$cport" ] && continue
    hport="$(_pick_port "$cport")"
    [ -n "$hport" ] && pflags="$pflags -p ${hport}:${cport}"
  done

  # shellcheck disable=SC2086
  if capture docker run -d --name "$cname" --network "$DOCKER_NET" --restart unless-stopped $pflags "$image"; then
    _record_launched "$winapp" "$image" "$cname" "$note"
    mark_ok "$winapp" "container launched: $cname"
  else
    mark_fail "$winapp" "${LAST_ERR:-could not start container for $image}"
  fi
}

# Purple "Launched containers" section (one line per container). Printed at the end
# of a run by execute_all (orchestrated) or print_summary (standalone stage).
print_launched_containers() {
  local f="${DOCKER_LAUNCHED:-/tmp/migrate_to_linux_launched.tsv}"
  [ -s "$f" ] || return 0
  printf '\n' >&3
  printf '        \033[1;35m===== Launched containers =====\033[0m\n' >&3
  local winapp image cname howto
  while IFS="$(printf '\t')" read -r winapp image cname howto; do
    [ -z "$cname" ] && continue
    info "          ${winapp}  --> image:'${image}' | container: '${cname}' | How to use: ${howto}"
  done < "$f"
}


# Manual-download apps with no automatic installer (format: "Windows app|hint").
# Handled at the very END so they never block the unattended stages.
MANUAL_APPS=(
  "Gurobi|Gurobi (Linux)|Gurobi Optimizer (academic/commercial) from gurobi.com|https://www.gurobi.com/downloads/gurobi-software/|1"
  "PaperCut Print Deploy Client|PaperCut Print Deploy (Linux)|PaperCut Print Deploy client from your print server's portal|https://www.papercut.com/products/ng/print-deploy/|1"
  "RealVNC Viewer|RealVNC Viewer (Linux)|RealVNC Viewer (.deb/.rpm)|https://www.realvnc.com/en/connect/download/viewer/|0"
  "RStudio|RStudio (Linux)|RStudio Desktop (.deb/.rpm) from posit.co|https://posit.co/download/rstudio-desktop/|0"
  "SpotPlayer|SpotPlayer (Linux)|SpotPlayer (Sib) Linux build from sibm[a].ir|https://www.sibmaster.ir/|0"
  "VMware Workstation|VMware Workstation Pro (Linux)|VMware Workstation Pro .bundle (free for personal use)|https://www.vmware.com/products/workstation-pro.html|0"
  "Rufus|Ventoy|Ventoy from ventoy.net; GUI alt: 'popsicle'|https://www.ventoy.net/en/download.html|0"
)

# Windows apps that were detected but NOT found in the manifest (no Linux mapping).
UNMATCHED_APPS=(
  "NordUpdater"
  "Python Launcher"
  "Windows Software Development Kit - Windows 10.0.26100.7705"
  "Windows Software Development Kit - Windows 10.0.26100.8249"
  "Python Manager"
)

here=""

# Yes/No question. The question text AND (y/n) are always printed to the terminal.
ask() {  # ask "Question text" [default y|n]   -> 0 = yes, 1 = no
  local q="$1" def="${2:-y}" ans
  if [ ! -r /dev/tty ]; then case "$def" in [Yy]*) return 0 ;; *) return 1 ;; esac; fi
  while :; do
    printf '  %s (y/n): ' "$q" > /dev/tty
    if ! read -r ans < /dev/tty; then case "$def" in [Yy]*) return 0 ;; *) return 1 ;; esac; fi
    case "$ans" in
      [Yy]|[Yy][Ee][Ss]) return 0 ;;
      [Nn]|[Nn][Oo])     return 1 ;;
      *) printf '\033[1;31m  Please answer y or n.\033[0m\n' > /dev/tty ;;
    esac
  done
}

# Numeric question. Prints the question text, reads a whole number (>= 0).
# Echoes the chosen number on stdout.
ask_number() {  # ask_number "Question text" [default]
  local q="$1" def="${2:-1}" ans
  if [ ! -r /dev/tty ]; then printf '%s' "$def"; return 0; fi
  while :; do
    printf '  %s ' "$q" > /dev/tty
    if ! read -r ans < /dev/tty; then printf '%s' "$def"; return 0; fi
    [ -z "$ans" ] && ans="$def"
    case "$ans" in
      *[!0-9]*) printf '\033[1;31m  Please enter a whole number.\033[0m\n' > /dev/tty ;;
      *)        printf '%s' "$ans"; return 0 ;;
    esac
  done
}

# Two-choice (a/b) question. Shows the question and both labelled options, reads a/b,
# and echoes "same" for a or "latest" for b (default latest when no terminal).
ask_ab() {  # ask_ab "Question" "Option a label" "Option b label"
  local q="$1" la="$2" lb="$3" ans
  if [ ! -r /dev/tty ]; then printf 'latest'; return 0; fi
  printf '\n  %s\n' "$q"  > /dev/tty
  printf '    a. %s\n' "$la" > /dev/tty
  printf '    b. %s\n' "$lb" > /dev/tty
  while :; do
    printf '  Choose (a/b): ' > /dev/tty
    if ! read -r ans < /dev/tty; then printf 'latest'; return 0; fi
    case "$ans" in
      [Aa]) printf 'same';   return 0 ;;
      [Bb]) printf 'latest'; return 0 ;;
      *)    printf '\033[1;31m  Please answer a or b.\033[0m\n' > /dev/tty ;;
    esac
  done
}

# Display a saved config file as question/answer lines.
show_config() {  # show_config CONFIG_FILE
  local cfg="$1" k v label
  printf '\n'; log "Reading from the config file $cfg:"
  while IFS='=' read -r k v; do
    case "$k" in \#*|'') continue ;; esac
    v="${v%%#*}"; v="$(printf '%s' "$v" | tr -d '[:space:]')"
    case "$k" in
      INSTALL_DRIVERS)   label="Install device drivers?" ;;
      INSTALL_APPS)      label="Install must-have software?" ;;
      BEST_ALTERNATIVES) label="How many best alternatives of an application to install (excluding wine - Windows emulator)?" ;;
      VERSION_MODE)      label="Version of application exact equivalents (Apps data restore might not be applicable with 'same' - same/latest)?" ;;
      UPDATE_EXISTING)   label="Update apps already installed on Linux?" ;;
      INSTALL_SECURITY)  label="Install security-suite equivalents?" ;;
      FREE_ONLY)         label="Only install free applications (skip paid)?" ;;
      WINE_NONCROSS)     label="Install the Windows-exclusive applications under the Windows emulator (wine) too?" ;;
      APPLY_SETTINGS)    label="Apply Windows settings?" ;;
      REBUILD_DOCKER)    label="Migrate docker components?" ;;
      *) continue ;;
    esac
    info "$label  $v"
  done < "$cfg"
}

# Apply a saved config: set do_* (caller's vars via dynamic scope) + MIGRATE_* env.
load_config() {  # load_config CONFIG_FILE
  local cfg="$1" k v
  while IFS='=' read -r k v; do
    case "$k" in \#*|'') continue ;; esac
    v="${v%%#*}"; v="$(printf '%s' "$v" | tr -d '[:space:]')"
    case "$k" in
      INSTALL_DRIVERS)   [ "$v" = y ] && do_drivers=1  || do_drivers=0 ;;
      INSTALL_APPS)      [ "$v" = y ] && do_apps=1     || do_apps=0 ;;
      BEST_ALTERNATIVES) MIGRATE_ALT_LIMIT="$v" ;;
      VERSION_MODE)      MIGRATE_VERSION_MODE="$v" ;;
      UPDATE_EXISTING)   [ "$v" = y ] && MIGRATE_UPDATE_EXISTING=yes  || MIGRATE_UPDATE_EXISTING=no ;;
      INSTALL_SECURITY)  [ "$v" = y ] && MIGRATE_INSTALL_SECURITY=yes || MIGRATE_INSTALL_SECURITY=no ;;
      FREE_ONLY)         [ "$v" = y ] && MIGRATE_FREE_ONLY=yes        || MIGRATE_FREE_ONLY=no ;;
      WINE_NONCROSS)     [ "$v" = y ] && MIGRATE_WINE_NONCROSS=yes    || MIGRATE_WINE_NONCROSS=no ;;
      APPLY_SETTINGS)    [ "$v" = y ] && do_settings=1 || do_settings=0 ;;
      REBUILD_DOCKER)    [ "$v" = y ] && do_docker=1   || do_docker=0 ;;
    esac
  done < "$cfg"
  : "${MIGRATE_ALT_LIMIT:=1}"; : "${MIGRATE_VERSION_MODE:=latest}"
  : "${MIGRATE_UPDATE_EXISTING:=no}"; : "${MIGRATE_INSTALL_SECURITY:=no}"; : "${MIGRATE_FREE_ONLY:=no}"
  : "${MIGRATE_WINE_NONCROSS:=no}"
  export MIGRATE_ALT_LIMIT MIGRATE_VERSION_MODE MIGRATE_UPDATE_EXISTING MIGRATE_INSTALL_SECURITY MIGRATE_FREE_ONLY MIGRATE_WINE_NONCROSS
  # docker rebuild only if a snapshot actually shipped with the installer
  [ -f "$here/submodules/docker_rebuild.sh" ] || do_docker=0
}

# Write the current answers (do_* + MIGRATE_*) back to the config file so a manual
# run updates it for next time.
yn() { [ "$1" = "1" ] && printf 'y' || printf 'n'; }   # 1 -> y, anything else -> n
save_config() {  # save_config CONFIG_FILE
  local cfg="$1"
  {
    printf '%s\n' '# Migrate to Linux -- saved answers for execute_all.sh'
    printf '%s\n' '# Edit these values, or delete this file to be asked each question interactively.'
    printf '%s\n' '# Yes/No = y/n ; VERSION_MODE = same|latest ; BEST_ALTERNATIVES = a whole number.'
    printf 'INSTALL_DRIVERS=%s\n'   "$(yn "$do_drivers")"
    printf 'INSTALL_APPS=%s\n'      "$(yn "$do_apps")"
    printf 'BEST_ALTERNATIVES=%s\n' "${MIGRATE_ALT_LIMIT:-1}"
    printf 'VERSION_MODE=%s\n'      "${MIGRATE_VERSION_MODE:-latest}"
    printf 'UPDATE_EXISTING=%s\n'   "$([ "${MIGRATE_UPDATE_EXISTING:-no}" = yes ] && printf y || printf n)"
    printf 'INSTALL_SECURITY=%s\n'  "$([ "${MIGRATE_INSTALL_SECURITY:-no}" = yes ] && printf y || printf n)"
    printf 'FREE_ONLY=%s\n'         "$([ "${MIGRATE_FREE_ONLY:-no}" = yes ] && printf y || printf n)"
    printf 'WINE_NONCROSS=%s\n'     "$([ "${MIGRATE_WINE_NONCROSS:-no}" = yes ] && printf y || printf n)"
    printf 'APPLY_SETTINGS=%s\n'    "$(yn "$do_settings")"
    printf 'REBUILD_DOCKER=%s\n'    "$(yn "$do_docker")"
  } > "$cfg" 2>/dev/null && info "Saved your answers to the config file: $cfg"
}

# Warn about Windows apps with no manifest entry (no Linux equivalent was mapped).
show_unmatched_warning() {
  [ "${#UNMATCHED_APPS[@]}" -eq 0 ] && return 0
  printf '\n'
  warn "WARNING: these apps were detected on Windows but were NOT found in the migration repository's manifest,"
  warn "so no Linux equivalent will be installed for them:"
  local a
  for a in "${UNMATCHED_APPS[@]}"; do info "  - $a"; done
  warn "To include them, add entries to the manifest file:"
  warn "    documents/B_applications.json"
  warn "then re-run run_project.ps1 on your Windows machine and use the regenerated 'Execute on Linux!' scripts."
  # Record them so they appear as a dedicated skip group in the final summary.
  local prev="$MODULE"; MODULE="Applications"
  for a in "${UNMATCHED_APPS[@]}"; do record_line SKIP "$a" "not in the manifest"; done
  MODULE="$prev"
}

run_stage() {  # run_stage script.sh [args...]  (helper scripts live in submodules/)
  local step="$1"; shift
  if [ -f "$here/submodules/$step" ]; then
    log "=== Running $step $* ==="
    bash "$here/submodules/$step" "$@" || warn "$step reported errors (continuing)"
  else
    warn "missing: submodules/$step"
  fi
}

# Manual downloads, handled LAST. For each app: show what to download and where to
# put it, then ask (done/skip). On 'done', verify the file is present and install
# it; if it is missing/unusable, show a red error and ask again until the file is
# correctly placed or the user types 'skip'.
install_manual_apps() {
  [ "${#MANUAL_APPS[@]}" -eq 0 ] && return 0
  MODULE="Applications"   # manual downloads are part of the Applications module
  local base="${MIGRATE_MANUAL_DIR:-$DOWNLOAD_DIR/manual}"
  printf '\n'; log "Manual downloads (apps with no automatic installer) -- done last"
  local entry name alt note url paid slug dir ans f skip_all=0
  for entry in "${MANUAL_APPS[@]}"; do
    IFS='|' read -r name alt note url paid <<< "$entry"
    # "skip all" chosen earlier: skip this and every remaining manual app without prompting.
    if [ "$skip_all" -eq 1 ]; then mark_skip "${alt:-$name}" "user skipped (skip all)"; continue; fi
    slug="$(slugify "$name")"; dir="$base/$slug"; mkdir -p "$dir"
    printf '\n\n'
    if [ -n "$alt" ]; then
      printf '\033[1;34m==> Manual install: %s   --->   %s\033[0m\n' "$name" "$alt" >&3
    else
      printf '\033[1;34m==> Manual install: %s\033[0m\n' "$name" >&3
    fi
    info "This app's installer cannot be downloaded automatically by the Migration Toolkit (it usually requires accepting a licence / signing in, or has no stable direct download link)."
    # Free-only mode: this manual app's only alternative is paid. Ask before continuing.
    if [ "${MIGRATE_FREE_ONLY:-no}" = "yes" ] && [ "${paid:-0}" = "1" ]; then
      if [ -r /dev/tty ]; then
        printf '  No free alternative exists for this application. Do you want to continue with the installation of the paid one? Answering with No means skipping this application (y/n): ' > /dev/tty
        read -r ans < /dev/tty || ans="n"
        case "$ans" in [Yy]*) ;; *) mark_skip "${alt:-$name}" "paid - skipped (free-only mode)"; continue ;; esac
      else
        mark_skip "${alt:-$name}" "paid - skipped (free-only mode)"; continue
      fi
    fi
    [ -n "$note" ] && info "$note"
    # Download-page stage: health-check the saved URL and open it, else fall back to a search.
    open_download_page "${alt:-$name}" "$url"
    info "Download the installer (unzip it first if it is zipped)."
    info "Then type its path in single quotes -- either a full path, or one relative to ${TARGET_HOME}/Downloads."
    info "Any valid installer extension works (.deb/.rpm/.sh/.run/.bin/.bundle/.AppImage/.tar.gz/.zip/...);"
    info "'skip' to skip this app, or 'skip all' to skip this and every remaining manual app."
    if [ ! -r /dev/tty ]; then mark_skip "${alt:-$name}" "no tty for manual prompt"; continue; fi
    while :; do
      printf "  %s ('installer path'/s=skip/a=skip all): " "${alt:-$name}" > /dev/tty
      read -r ans < /dev/tty || ans="skip"
      case "$ans" in
        [Aa]|[Aa][Ll][Ll]|[Ss][Kk][Ii][Pp][Aa][Ll][Ll]|'skip all'|'Skip all'|'Skip All'|'SKIP ALL')
          skip_all=1; mark_skip "${alt:-$name}" "user skipped (skip all)"; break ;;
        [Ss]|[Ss][Kk][Ii][Pp])
          mark_skip "${alt:-$name}" "user skipped"; break ;;
        *)
          f="$(resolve_user_path "$ans")"
          if [ -z "$f" ] || [ ! -f "$f" ] || [ ! -r "$f" ]; then
            printf "\033[1;31m  No readable file at that path -- type the path in single quotes (e.g. '%s/Downloads/app.deb'), or skip.\033[0m\n" "$TARGET_HOME" > /dev/tty
            continue
          fi
          LAST_ERR=""
          if install_by_ext "$f"; then
            mark_ok "$name" "installed from $f" "$alt"; break
          else
            printf "\033[1;31m  %s -- fix the file and re-enter its path, or skip.\033[0m\n" "${LAST_ERR:-could not handle the file}" > /dev/tty
          fi
          ;;
      esac
    done
  done
}

# Print the summary for ONE module from the shared log (fields: date,module,status,name,detail).
print_module_summary() {  # print_module_summary "Module name"
  local f="${RESULTS:-/tmp/migrate_to_linux_results.tsv}" m="$1"
  awk -F'\t' -v m="$m" '$2==m{found=1} END{exit !found}' "$f" || return 0
  local nok nskip nman nfail nunver nplan
  nok=$(awk   -F'\t' -v m="$m" '$2==m{g=$3;gsub(/ /,"",g); if(g=="OK")c++}     END{print c+0}' "$f")
  nskip=$(awk -F'\t' -v m="$m" '$2==m{g=$3;gsub(/ /,"",g); if(g=="SKIP")c++}   END{print c+0}' "$f")
  nman=$(awk  -F'\t' -v m="$m" '$2==m{g=$3;gsub(/ /,"",g); if(g=="MANUAL")c++} END{print c+0}' "$f")
  nfail=$(awk -F'\t' -v m="$m" '$2==m{g=$3;gsub(/ /,"",g); if(g=="FAIL")c++}   END{print c+0}' "$f")
  nunver=$(awk -F'\t' -v m="$m" '$2==m{g=$3;gsub(/ /,"",g); if(g=="UNVER")c++} END{print c+0}' "$f")
  nplan=$(awk  -F'\t' -v m="$m" '$2==m{g=$3;gsub(/ /,"",g); if(g=="PLAN")c++}  END{print c+0}' "$f")
  printf '\n'
  # purple, extra-indented section title
  printf '        \033[1;35m===== %s summary =====\033[0m\n' "$m" >&3
  [ "$nplan" -gt 0 ] && info "          Planned   : $nplan (dry-run)"
  ok   "          Succeeded : $nok"
  info "          Skipped   : $nskip"
  warn "          Manual    : $nman"
  warn "          Unverified: $nunver"
  err  "          Failed    : $nfail"
  if [ "$nunver" -gt 0 ]; then
    warn "          Installed but UNVERIFIED:"
    awk -F'\t' -v m="$m" '{g=$3;gsub(/ /,"",g)} $2==m && g=="UNVER"{printf "            - %s: %s\n",$4,$5}' "$f" >&3
  fi
  if [ "$nplan" -gt 0 ]; then
    info "          Planned installs (dry-run):"
    awk -F'\t' -v m="$m" '{g=$3;gsub(/ /,"",g)} $2==m && g=="PLAN"{printf "            - %s: %s\n",$4,$5}' "$f" >&3
  fi
  if [ "$nfail" -gt 0 ]; then
    err "          Failures (1-line reason each):"
    awk -F'\t' -v m="$m" '{g=$3;gsub(/ /,"",g)} $2==m && g=="FAIL"{printf "            - %s: %s\n",$4,$5}' "$f" >&3
  fi
  if [ "$nman" -gt 0 ]; then
    warn "          Manual steps still needed:"
    awk -F'\t' -v m="$m" '{g=$3;gsub(/ /,"",g)} $2==m && g=="MANUAL"{printf "            - %s: %s\n",$4,$5}' "$f" >&3
  fi
  if [ "$nskip" -gt 0 ]; then
    # Group skipped items by their reason: "Skipped: <reason>" with its items beneath.
    local r
    while IFS= read -r r; do
      [ -z "$r" ] && continue
      printf '                 \033[38;5;208mSkipped: %s\033[0m\n' "$(hl_already "$r" $'\033[38;5;208m')" >&3
      awk -F'\t' -v m="$m" -v rr="$r" '{g=$3;gsub(/ /,"",g); d=$5; if(d=="")d="already present"} $2==m && g=="SKIP" && d==rr{printf "            - %s\n",$4}' "$f" >&3
    done < <(awk -F'\t' -v m="$m" '{g=$3;gsub(/ /,"",g); d=$5; if(d=="")d="already present"} $2==m && g=="SKIP"{print d}' "$f" | sort -u)
  fi
  # Apps that now exist on the machine (installed this run or already present), each
  # with a one-line how-to-open note (field 6 of the results log).
  if awk -F'\t' -v m="$m" '$2==m && $6!=""{f=1} END{exit !f}' "$f"; then
    printf '                 \033[1;32mApplications on this machine - how to open each:\033[0m\n' >&3
    local _bl=$'\033[1;34m' _rs=$'\033[0m'
    awk -F'\t' -v m="$m" -v bl="$_bl" -v rs="$_rs" '$2==m && $6!=""{n=($7!="" && $7!=$4 ? $7" ("$4")" : $4); printf "            - %s%s%s: %s\n",bl,n,rs,$6}' "$f" | sort -u >&3
  fi
}

# Final summary: comes after everything else, classified per big module in the order
# they ran (Drivers -> Config settings -> Applications).
print_combined_summary() {
  local f="${RESULTS:-/tmp/migrate_to_linux_results.tsv}"
  printf '\n\n'
  log "==================== FINAL SUMMARY ===================="
  if [ ! -s "$f" ]; then info "No operations were recorded."; return 0; fi
  print_module_summary "Drivers"
  print_module_summary "Config settings"
  print_module_summary "Applications"
  print_launched_containers
  write_uninstall_script
  printf '\n'
  info "Full log: $f"
}

main() {
  clear 2>/dev/null || printf '\033[2J\033[3J\033[H'
  mega_title
  # Report-only mode: --dry-run / --report-only / -n (or MIGRATE_DRY_RUN=yes) prints the
  # plan and makes no changes; it does not need root.
  local arg
  for arg in "$@"; do
    case "$arg" in --dry-run|--report-only|-n) MIGRATE_DRY_RUN=yes ;; esac
  done
  export MIGRATE_DRY_RUN="${MIGRATE_DRY_RUN:-no}"
  if is_dry_run; then log "DRY-RUN (report only): showing the plan; no changes will be made."; else require_root; fi
  detect_distro
  detect_arch
  here="$(cd "$(dirname "$0")" && pwd)"

  # Share ONE results log across all stages so the final summary covers everything.
  export RESULTS="${RESULTS:-/tmp/migrate_to_linux_results.tsv}"
  : > "$RESULTS" 2>/dev/null || true
  # Shared log of containers launched by the docker install method (req28).
  export DOCKER_LAUNCHED="${DOCKER_LAUNCHED:-/tmp/migrate_to_linux_launched.tsv}"
  : > "$DOCKER_LAUNCHED" 2>/dev/null || true
  # Shared install ledger -> the uninstall script written at the end of the run.
  export LEDGER="${LEDGER:-/tmp/migrate_to_linux_ledger.tsv}"
  : > "$LEDGER" 2>/dev/null || true
  export MIGRATE_KEEP_RESULTS=1
  # Where C_detect staged the user's personal files (used by the post settings phase).
  export MIGRATE_STAGE="${MIGRATE_STAGE:-$here/migrated_user_data}"

  log "Migrate to Linux  --  Run All"
  info "Distribution : ${DISTRO_NAME}"
  info "Family / pm  : ${FAMILY} / ${PM}"
  info "Architecture : ${ARCH}"

  show_unmatched_warning

  # Decryption password for sensitive exported data: ask ONCE, up front, before the
  # setup questions. The WiFi/SSH/Contacts restore steps reuse it (MIGRATE_XFER_PWD).
  ask_xfer_password

  # ---- Configuration: from the saved config file, or by asking each question ----
  local do_drivers=0 do_apps=0 do_settings=0 do_docker=0
  local cfg="$here/migrate.config" use_cfg=0
  if [ -f "$cfg" ]; then
    show_config "$cfg"
    printf '\n'
    if [ -r /dev/tty ]; then
      ask $'Do you want to continue with these configurations\n (Choose N to answer them again, subsequently, the default values will change to your answers)?' y && use_cfg=1
    else
      use_cfg=1
    fi
  fi

  if [ "$use_cfg" -eq 1 ]; then
    load_config "$cfg"
    info "Using the saved configuration above."
  else
    log "Setup questions (answer each one; the install then runs unattended):"
    ask "(1/10) Install device drivers?"     y && do_drivers=1
    ask "(2/10) Install must-have software?" y && do_apps=1
    if [ "$do_apps" -eq 1 ]; then
      MIGRATE_ALT_LIMIT="$(ask_number "(3/10) How many (if applicable) best alternatives of an application do you want to install (excluding wine - Windows emulator)?" 1)"
      export MIGRATE_ALT_LIMIT
      MIGRATE_VERSION_MODE="$(ask_ab "(4/10) Want to install same version of exact equivalents from Windows to Linux or the latest version? (Apps data restore might not be applicable with 'same')" "Same version" "Latest version")"
      export MIGRATE_VERSION_MODE
      if ask "(5/10) Update apps that are already installed on Linux?" n; then MIGRATE_UPDATE_EXISTING=yes; else MIGRATE_UPDATE_EXISTING=no; fi
      export MIGRATE_UPDATE_EXISTING
      if ask "(6/10) Install security-suite equivalents (antivirus, extra firewall, etc.)? Linux is hardened by default, so many users skip these." n; then MIGRATE_INSTALL_SECURITY=yes; else MIGRATE_INSTALL_SECURITY=no; fi
      export MIGRATE_INSTALL_SECURITY
      if ask "(7/10) Do you want to only install free applications and skip paid alternatives?" n; then MIGRATE_FREE_ONLY=yes; else MIGRATE_FREE_ONLY=no; fi
      export MIGRATE_FREE_ONLY
    fi
    ask "(8/10) Apply Windows os-wide settings?"     y && do_settings=1
    if [ -f "$here/submodules/docker_rebuild.sh" ]; then
      ask "(9/10) Migrate docker components (If you have installed docker on Windows - images, volumes, containers, networks, etc.)?" y && do_docker=1
    fi
    if [ "$do_apps" -eq 1 ]; then
      if ask "(10/10) Install the Windows-exclusive applications under the Windows emulator (wine) too?" n; then MIGRATE_WINE_NONCROSS=yes; else MIGRATE_WINE_NONCROSS=no; fi
      export MIGRATE_WINE_NONCROSS
    fi
    # Answered manually -> persist these answers as the new config defaults
    # (skipped in dry-run so the report-only mode changes nothing on disk).
    is_dry_run || save_config "$cfg"
  fi

  # ---- Run the selected stages.  In dry-run only the apps plan is simulated (the
  #      driver, settings and docker stages make system changes, so they are skipped). ----
  if is_dry_run; then
    [ "$do_apps" -eq 1 ] && run_stage install_must_have_software.sh
    [ "$do_apps" -eq 1 ] && install_manual_apps
    info "Dry-run: device-driver, settings and docker stages are not simulated."
  else
    # Order: drivers -> settings(pre) -> apps -> manual -> settings(post) -> docker.
    # Settings split into two phases: "pre" before apps, then "post" (shortcuts/pins,
    # ~/.ssh, Contacts) after apps+manual so it can resolve installed-app equivalents.
    [ "$do_drivers"  -eq 1 ] && run_stage install_device_drivers.sh
    [ "$do_settings" -eq 1 ] && run_stage apply_settings.sh pre
    [ "$do_apps"     -eq 1 ] && run_stage install_must_have_software.sh
    # ---- Manual downloads (part of the apps stage) ----
    [ "$do_apps" -eq 1 ] && install_manual_apps
    # ---- Post-install settings: shortcuts/favourites, ~/.ssh, Contacts ----
    [ "$do_settings" -eq 1 ] && run_stage apply_settings.sh post
    # ---- Restore the user & application data backup (self-gating: prompts for the
    #      archive path, 's' to skip). Runs after apps+settings so home dirs exist. ----
    [ -f "$here/submodules/restore_user_and_application_data.sh" ] && run_stage restore_user_and_application_data.sh
    # ---- Docker rebuild last (needs Docker, which the apps stage installs) ----
    if [ "$do_docker" -eq 1 ]; then
      log "=== Running docker_rebuild.sh ==="
      bash "$here/submodules/docker_rebuild.sh" || warn "docker_rebuild.sh reported errors"
    fi
  fi

  print_combined_summary

  printf '\n'; log "All steps finished."
}

main "$@"
